type CronField = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

type FieldConfig = {
  readonly min: number;
  readonly max: number;
  readonly name: keyof CronField;
};

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute",     min: 0,  max: 59 },
  { name: "hour",       min: 0,  max: 23 },
  { name: "dayOfMonth", min: 1,  max: 31 },
  { name: "month",      min: 1,  max: 12 },
  { name: "dayOfWeek",  min: 0,  max: 7  },
] as const;

const VALID_SEGMENT_RE = /^[\d\-\*\/]+$/;

function buildRange(start: number, end: number): number[] {
  if (start > end) {
    throw new Error(`Range start (${start}) must not exceed end (${end})`);
  }
  const result: number[] = [];
  for (let i = start; i <= end; i++) {
    result.push(i);
  }
  return result;
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new Error(
      `Value ${value} in "${context}" is out of valid range [${min}, ${max}]`
    );
  }
}

function parseIntStrict(raw: string, context: string): number {
  const trimmed = raw.trim();
  if (trimmed === "" || !/^\d+$/.test(trimmed)) {
    throw new Error(`Expected an integer in "${context}", got: "${trimmed}"`);
  }
  const value = Number(trimmed);
  if (!Number.isInteger(value)) {
    throw new Error(`Non-integer number in "${context}": "${trimmed}"`);
  }
  return value;
}

function parseRangePart(raw: string, min: number, max: number): [number, number] {
  const dashParts = raw.split("-");
  if (dashParts.length !== 2) {
    throw new Error(`Invalid range expression: "${raw}"`);
  }
  const start = parseIntStrict(dashParts[0], raw);
  const end = parseIntStrict(dashParts[1], raw);
  assertInRange(start, min, max, raw);
  assertInRange(end, min, max, raw);
  if (start > end) {
    throw new Error(`Range start (${start}) exceeds end (${end}) in "${raw}"`);
  }
  return [start, end];
}

function parseSegment(segment: string, min: number, max: number): number[] {
  if (!VALID_SEGMENT_RE.test(segment)) {
    throw new Error(`Invalid characters in segment: "${segment}"`);
  }

  // Step expression: */N  or  N-M/N  or  N/N
  if (segment.includes("/")) {
    const slashIndex = segment.indexOf("/");
    const lastSlash = segment.lastIndexOf("/");
    if (slashIndex !== lastSlash) {
      throw new Error(`Multiple slashes in segment: "${segment}"`);
    }
    const rangePart = segment.slice(0, slashIndex);
    const stepPart = segment.slice(slashIndex + 1);

    if (stepPart === "") {
      throw new Error(`Missing step value after "/" in "${segment}"`);
    }
    const step = parseIntStrict(stepPart, segment);
    if (step <= 0) {
      throw new Error(`Step value must be >= 1 in "${segment}", got: ${step}`);
    }

    let start: number;
    let end: number;

    if (rangePart === "*") {
      start = min;
      end = max;
    } else if (rangePart.includes("-")) {
      [start, end] = parseRangePart(rangePart, min, max);
    } else {
      start = parseIntStrict(rangePart, segment);
      assertInRange(start, min, max, segment);
      end = max;
    }

    const result: number[] = [];
    for (let i = start; i <= end; i += step) {
      result.push(i);
    }
    return result;
  }

  // Wildcard
  if (segment === "*") {
    return buildRange(min, max);
  }

  // Range: N-M
  if (segment.includes("-")) {
    const [start, end] = parseRangePart(segment, min, max);
    return buildRange(start, end);
  }

  // Plain number
  const value = parseIntStrict(segment, segment);
  assertInRange(value, min, max, segment);
  return [value];
}

function parseField(raw: string, config: FieldConfig): number[] {
  if (raw.trim() === "") {
    throw new Error(`Field "${config.name}" is empty`);
  }

  const segments = raw.split(",");
  if (segments.length === 0) {
    throw new Error(`Field "${config.name}" produced no segments`);
  }

  const seen = new Set<number>();
  for (const segment of segments) {
    const trimmed = segment.trim();
    if (trimmed === "") {
      throw new Error(`Empty segment (dangling comma?) in field "${config.name}": "${raw}"`);
    }
    const values = parseSegment(trimmed, config.min, config.max);
    if (values.length === 0) {
      throw new Error(
        `Segment "${trimmed}" in field "${config.name}" produced no values`
      );
    }
    for (const v of values) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronField {
  if (expression == null || typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, got: ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new Error("Cron expression must not be empty or whitespace-only");
  }

  const parts = trimmed.split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${parts.length}: "${trimmed}"`
    );
  }

  const result = {} as CronField;
  for (let i = 0; i < FIELD_CONFIGS.length; i++) {
    const config = FIELD_CONFIGS[i];
    try {
      result[config.name] = parseField(parts[i], config);
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      throw new Error(
        `Failed to parse field "${config.name}" (position ${i + 1}, value: "${parts[i]}"): ${message}`
      );
    }
  }

  return result;
}

interface Node<T> {
  key: string;
  value: T;
  prev: Node<T> | null;
  next: Node<T> | null;
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;
  private head: Node<T>; // most recently used sentinel
  private tail: Node<T>; // least recently used sentinel

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 1) {
      throw new RangeError(`LRUCache capacity must be a positive integer, got: ${capacity}`);
    }

    this.capacity = capacity;
    this.map = new Map();

    // Sentinel nodes eliminate null-checks on boundary conditions
    this.head = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.tail = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key: string): T | undefined {
    if (typeof key !== "string") {
      return undefined;
    }

    const node = this.map.get(key);
    if (node === undefined) {
      return undefined;
    }

    this.moveToFront(node);
    return node.value;
  }

  set(key: string, value: T): void {
    if (typeof key !== "string") {
      throw new TypeError(`LRUCache key must be a string, got: ${typeof key}`);
    }

    const existing = this.map.get(key);

    if (existing !== undefined) {
      existing.value = value;
      this.moveToFront(existing);
      return;
    }

    const node: Node<T> = { key, value, prev: null, next: null };
    this.map.set(key, node);
    this.insertAtFront(node);

    if (this.map.size > this.capacity) {
      this.evictLRU();
    }
  }

  get size(): number {
    return this.map.size;
  }

  has(key: string): boolean {
    if (typeof key !== "string") {
      return false;
    }
    return this.map.has(key);
  }

  delete(key: string): boolean {
    if (typeof key !== "string") {
      return false;
    }

    const node = this.map.get(key);
    if (node === undefined) {
      return false;
    }

    this.removeNode(node);
    this.map.delete(key);
    return true;
  }

  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  private insertAtFront(node: Node<T>): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  private removeNode(node: Node<T>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    node.prev = null;
    node.next = null;
  }

  private moveToFront(node: Node<T>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  private evictLRU(): void {
    const lru = this.tail.prev;
    if (lru === null || lru === this.head) {
      return; // empty list — should never happen under normal use
    }
    this.removeNode(lru);
    this.map.delete(lru.key);
  }
}

type Primitive = string | number | boolean | null | undefined | symbol | bigint;
type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  input: PlainObject,
  prefix = "",
  seen = new WeakSet<object>()
): Record<string, Primitive> {
  if (!isPlainObject(input)) {
    throw new TypeError(`Expected a plain object, received: ${typeof input}`);
  }

  if (seen.has(input)) {
    throw new Error(
      `Circular reference detected at key: "${prefix || "(root)"}`
    );
  }

  seen.add(input);

  const result: Record<string, Primitive> = {};
  const keys = Object.keys(input);

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(input, key)) continue;

    const value = input[key];
    const fullKey = prefix ? `${prefix}.${key}` : key;

    if (isPlainObject(value) && Object.keys(value).length > 0) {
      const nested = flattenObject(value, fullKey, seen);
      for (const nestedKey of Object.keys(nested)) {
        result[nestedKey] = nested[nestedKey];
      }
    } else {
      result[fullKey] = value as Primitive;
    }
  }

  seen.delete(input);

  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined | bigint | symbol;

type FlattenedObject = Record<string, Primitive>;

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  input: unknown,
  prefix = "",
  result: FlattenedObject = {},
  visited = new WeakSet<object>()
): FlattenedObject {
  if (input === null || input === undefined) {
    if (prefix !== "") {
      result[prefix] = input as null | undefined;
    }
    return result;
  }

  if (!isPlainObject(input)) {
    if (prefix !== "") {
      result[prefix] = input as Primitive;
    }
    return result;
  }

  if (visited.has(input as object)) {
    throw new TypeError(
      `Circular reference detected at key: "${prefix || "(root)"}"`
    );
  }

  visited.add(input as object);

  const entries = Object.entries(input as Record<string, unknown>);

  if (entries.length === 0) {
    if (prefix !== "") {
      result[prefix] = undefined;
    }
    return result;
  }

  for (const [key, value] of entries) {
    if (key === "" || key.includes(".")) {
      throw new TypeError(
        `Key "${key}" contains a dot or is empty, which would produce ambiguous flattened keys.`
      );
    }

    const newKey = prefix === "" ? key : `${prefix}.${key}`;

    if (isPlainObject(value)) {
      flattenObject(value, newKey, result, visited);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  visited.delete(input as object);

  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined | symbol | bigint;
type NestedObject = { [key: string]: unknown };
type FlatObject = { [key: string]: Primitive | unknown[] | object };

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenInto(
  input: NestedObject,
  result: FlatObject,
  prefix: string,
  ancestors: WeakSet<object>
): void {
  const entries = Object.entries(input);

  if (entries.length === 0) {
    // Empty object: preserve the key with its value rather than silently dropping it
    if (prefix !== "") {
      (result as NestedObject)[prefix] = {};
    }
    return;
  }

  for (const [key, value] of entries) {
    // Guard against keys containing dots — escape them to avoid ambiguous paths
    const safeKey = key.replace(/\./g, "\\.");
    const fullKey = prefix !== "" ? `${prefix}.${safeKey}` : safeKey;

    if (isPlainObject(value)) {
      if (ancestors.has(value)) {
        // Circular reference detected — store a sentinel rather than infinitely recurse
        (result as NestedObject)[fullKey] = "[Circular]";
        continue;
      }
      ancestors.add(value);
      flattenInto(value, result, fullKey, ancestors);
      ancestors.delete(value);
    } else {
      // Leaf: arrays, Dates, RegExps, primitives, null, undefined — all stored as-is
      (result as NestedObject)[fullKey] = value;
    }
  }
}

export default function flattenObject(input: NestedObject): FlatObject {
  if (!isPlainObject(input)) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${
        input === null ? "null" : typeof input
      }`
    );
  }

  const result: FlatObject = {};
  const ancestors = new WeakSet<object>();
  ancestors.add(input);
  flattenInto(input, result, "", ancestors);
  return result;
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, { min: number; max: number }> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
};

const FIELD_NAMES = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"] as const;

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of valid range [${min}, ${max}] for field "${context}"`
    );
  }
}

function deduplicateAndSort(values: number[]): number[] {
  return [...new Set(values)].sort((a, b) => a - b);
}

function parseNumber(token: string, min: number, max: number, context: string): number {
  const trimmed = token.trim();
  if (!/^\d+$/.test(trimmed)) {
    throw new SyntaxError(`Invalid numeric value "${trimmed}" in field "${context}"`);
  }
  const value = parseInt(trimmed, 10);
  assertInRange(value, min, max, context);
  return value;
}

function parseWildcard(min: number, max: number): number[] {
  return Array.from({ length: max - min + 1 }, (_, i) => min + i);
}

function parseStep(token: string, min: number, max: number, context: string): number[] {
  const [baseToken, stepToken] = token.split("/");

  if (stepToken === undefined || stepToken === "") {
    throw new SyntaxError(`Missing step value after "/" in field "${context}"`);
  }

  if (!/^\d+$/.test(stepToken.trim())) {
    throw new SyntaxError(`Invalid step value "${stepToken}" in field "${context}"`);
  }

  const step = parseInt(stepToken.trim(), 10);
  if (step <= 0) {
    throw new RangeError(`Step value must be a positive integer in field "${context}"`);
  }

  let rangeMin: number;
  let rangeMax: number;

  if (baseToken === "*") {
    rangeMin = min;
    rangeMax = max;
  } else if (baseToken.includes("-")) {
    const [start, end] = parseRange(baseToken, min, max, context);
    rangeMin = start;
    rangeMax = end;
  } else {
    rangeMin = parseNumber(baseToken, min, max, context);
    rangeMax = max;
  }

  const values: number[] = [];
  for (let i = rangeMin; i <= rangeMax; i += step) {
    values.push(i);
  }

  return values;
}

function parseRange(token: string, min: number, max: number, context: string): [number, number] {
  const parts = token.split("-");
  if (parts.length !== 2) {
    throw new SyntaxError(
      `Invalid range expression "${token}" in field "${context}": expected exactly one "-"`
    );
  }
  const start = parseNumber(parts[0], min, max, context);
  const end = parseNumber(parts[1], min, max, context);
  if (start > end) {
    throw new RangeError(
      `Range start ${start} must not exceed range end ${end} in field "${context}"`
    );
  }
  return [start, end];
}

function parseToken(token: string, min: number, max: number, context: string): number[] {
  const trimmed = token.trim();

  if (trimmed === "") {
    throw new SyntaxError(`Empty token encountered in field "${context}"`);
  }

  // Wildcard with optional step: * or */n
  if (trimmed === "*") {
    return parseWildcard(min, max);
  }

  // Step expression: */n or a-b/n or n/n
  if (trimmed.includes("/")) {
    return parseStep(trimmed, min, max, context);
  }

  // Range: a-b
  if (trimmed.includes("-")) {
    const [start, end] = parseRange(trimmed, min, max, context);
    return Array.from({ length: end - start + 1 }, (_, i) => start + i);
  }

  // Plain number
  return [parseNumber(trimmed, min, max, context)];
}

function parseField(expression: string, min: number, max: number, context: string): number[] {
  const trimmed = expression.trim();

  if (trimmed === "") {
    throw new SyntaxError(`Field "${context}" is empty`);
  }

  // Comma-separated list
  const parts = trimmed.split(",");
  const values: number[] = [];

  for (const part of parts) {
    if (part.trim() === "") {
      throw new SyntaxError(`Empty element in comma-separated list for field "${context}"`);
    }
    const parsed = parseToken(part, min, max, context);
    values.push(...parsed);
  }

  // Normalize dayOfWeek: treat 7 as Sunday (0)
  const normalized =
    context === "dayOfWeek"
      ? values.map((v) => (v === 7 ? 0 : v))
      : values;

  return deduplicateAndSort(normalized);
}

export function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(`Expected a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();

  if (trimmed === "") {
    throw new SyntaxError("Cron expression must not be empty");
  }

  // Split on whitespace, collapsing multiple spaces/tabs
  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${trimmed}"`
    );
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_NAMES.length; i++) {
    const name = FIELD_NAMES[i];
    const { min, max } = FIELD_RANGES[name];
    result[name] = parseField(fields[i], min, max, name);
  }

  return result;
}

export default parseCron;

export interface ParsedCron {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type CronField = keyof ParsedCron;

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  }, // 0 and 7 both represent Sunday
};

const FIELD_ORDER: CronField[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

function parseInteger(s: string, context: string): number {
  const trimmed = s.trim();
  if (!/^\d+$/.test(trimmed)) {
    throw new Error(`Expected an integer but got "${s}" in "${context}"`);
  }
  return parseInt(trimmed, 10);
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of valid range [${min}, ${max}] in "${context}"`
    );
  }
}

function expandRange(
  start: number,
  end: number,
  step: number,
  min: number,
  max: number,
  context: string
): number[] {
  if (step < 1) {
    throw new RangeError(`Step must be >= 1, got ${step} in "${context}"`);
  }
  if (start > end) {
    throw new RangeError(
      `Range start ${start} must not exceed end ${end} in "${context}"`
    );
  }
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    // Guard: skip values that somehow fall outside the field's absolute bounds
    if (i >= min && i <= max) {
      values.push(i);
    }
  }
  return values;
}

function parseSegment(segment: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];
  const trimmed = segment.trim();

  if (trimmed === "") {
    throw new Error(`Empty segment encountered in field "${field}"`);
  }

  // Step expression: "*/n", "start/n", or "start-end/n"
  if (trimmed.includes("/")) {
    const slashIdx = trimmed.indexOf("/");
    const rangeStr = trimmed.slice(0, slashIdx);
    const stepStr  = trimmed.slice(slashIdx + 1);

    if (rangeStr === "" || stepStr === "") {
      throw new Error(`Malformed step expression "${trimmed}" in field "${field}"`);
    }

    const step = parseInteger(stepStr, trimmed);
    if (step < 1) {
      throw new RangeError(`Step must be >= 1, got ${step} in "${trimmed}"`);
    }

    if (rangeStr === "*") {
      return expandRange(min, max, step, min, max, trimmed);
    }

    if (rangeStr.includes("-")) {
      const dashIdx  = rangeStr.indexOf("-");
      const startStr = rangeStr.slice(0, dashIdx);
      const endStr   = rangeStr.slice(dashIdx + 1);

      if (startStr === "" || endStr === "") {
        throw new Error(`Malformed range "${rangeStr}" in "${trimmed}"`);
      }

      const start = parseInteger(startStr, trimmed);
      const end   = parseInteger(endStr,   trimmed);
      assertInRange(start, min, max, trimmed);
      assertInRange(end,   min, max, trimmed);
      return expandRange(start, end, step, min, max, trimmed);
    }

    // "n/step" — treat as "n-max/step"
    const start = parseInteger(rangeStr, trimmed);
    assertInRange(start, min, max, trimmed);
    return expandRange(start, max, step, min, max, trimmed);
  }

  // Wildcard
  if (trimmed === "*") {
    return expandRange(min, max, 1, min, max, trimmed);
  }

  // Range: "start-end"
  if (trimmed.includes("-")) {
    const dashIdx  = trimmed.indexOf("-");
    const startStr = trimmed.slice(0, dashIdx);
    const endStr   = trimmed.slice(dashIdx + 1);

    if (startStr === "" || endStr === "") {
      throw new Error(`Malformed range "${trimmed}" in field "${field}"`);
    }

    const start = parseInteger(startStr, trimmed);
    const end   = parseInteger(endStr,   trimmed);
    assertInRange(start, min, max, trimmed);
    assertInRange(end,   min, max, trimmed);
    return expandRange(start, end, 1, min, max, trimmed);
  }

  // Single number
  const value = parseInteger(trimmed, `field "${field}"`);
  assertInRange(value, min, max, `field "${field}"`);
  return [value];
}

function parseField(fieldStr: string, field: CronField): number[] {
  if (fieldStr === "") {
    throw new Error(`Field "${field}" is empty`);
  }

  const segments = fieldStr.split(",");
  const valueSet = new Set<number>();

  for (const segment of segments) {
    const values = parseSegment(segment, field);
    for (const v of values) {
      valueSet.add(v);
    }
  }

  // Normalize dayOfWeek: both 0 and 7 represent Sunday — collapse to 0
  if (field === "dayOfWeek" && valueSet.has(7)) {
    valueSet.delete(7);
    valueSet.add(0);
  }

  if (valueSet.size === 0) {
    throw new Error(`Field "${field}" produced no valid values from "${fieldStr}"`);
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: string): ParsedCron {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, received ${typeof expression}`);
  }

  const trimmed = expression.trim();

  if (trimmed === "") {
    throw new Error("Cron expression must not be empty");
  }

  // Split on any contiguous whitespace to tolerate tabs and multiple spaces
  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as ParsedCron;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    // Each field parse is isolated so a failure names the offending field clearly
    try {
      result[fieldName] = parseField(fields[i], fieldName);
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      throw new Error(`Invalid cron field "${fieldName}" ("${fields[i]}"): ${message}`);
    }
  }

  return result;
}

type Traversable = { [key: string]: unknown } | unknown[];
type FlatRecord = { [key: string]: unknown };

/**
 * Returns true only for plain objects (Object.prototype or null proto) and arrays.
 * Guards against Date, RegExp, Map, Set, etc. being recursed into.
 */
function isTraversable(value: unknown): value is Traversable {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return true;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flatten(
  input: Traversable,
  prefix: string,
  result: FlatRecord,
  seen: WeakSet<object>
): void {
  // Guard against circular references — mark and bail rather than infinitely recurse.
  if (seen.has(input)) {
    if (prefix !== "") result[prefix] = "[Circular]";
    return;
  }
  seen.add(input);

  const entries: [string, unknown][] = Array.isArray(input)
    ? input.map((v, i) => [String(i), v])
    : Object.keys(input).map((k) => [k, (input as Record<string, unknown>)[k]]);

  if (entries.length === 0) {
    // Empty object/array: nothing to flatten — preserve as a leaf so the key isn't lost.
    if (prefix !== "") result[prefix] = input;
  } else {
    for (const [key, value] of entries) {
      const newKey = prefix !== "" ? `${prefix}.${key}` : key;
      if (isTraversable(value)) {
        flatten(value, newKey, result, seen);
      } else {
        result[newKey] = value;
      }
    }
  }

  // Remove from seen on the way back up so sibling subtrees with the same
  // object reference don't get incorrectly flagged as circular.
  seen.delete(input);
}

function flattenObject(obj: Record<string, unknown>): FlatRecord {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${
        obj === null ? "null" : Array.isArray(obj) ? "array" : typeof obj
      }`
    );
  }
  const result: FlatRecord = {};
  flatten(obj, "", result, new WeakSet());
  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined | bigint | symbol;

type FlattenedObject = Record<string, Primitive>;

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  input: unknown,
  maxDepth: number = 100
): FlattenedObject {
  if (!isPlainObject(input)) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${
        input === null ? "null" : Array.isArray(input) ? "array" : typeof input
      }`
    );
  }

  const result: FlattenedObject = {};

  function recurse(current: unknown, prefix: string, depth: number): void {
    if (depth > maxDepth) {
      throw new RangeError(
        `flattenObject exceeded maximum depth of ${maxDepth}. Possible circular reference or deeply nested structure.`
      );
    }

    if (isPlainObject(current)) {
      const keys = Object.keys(current);

      // Leaf-level empty object: emit the prefix as-is with undefined value
      if (keys.length === 0) {
        if (prefix !== "") {
          result[prefix] = undefined;
        }
        return;
      }

      for (const key of keys) {
        if (!Object.prototype.hasOwnProperty.call(current, key)) continue;

        // Sanitise the key segment — dot-notation separates levels
        const safeKey = key.replace(/\./g, "\\.");
        const newPrefix = prefix === "" ? safeKey : `${prefix}.${safeKey}`;
        recurse(current[key], newPrefix, depth + 1);
      }
    } else {
      // Primitive (or array treated as primitive) — emit it directly
      result[prefix] = current as Primitive;
    }
  }

  recurse(input, "", 0);
  return result;
}

export default flattenObject;

class LRUCache<T> {
  private readonly capacity: number;
  private readonly cache: Map<string, T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity)) {
      throw new TypeError(`Capacity must be an integer, got: ${capacity}`);
    }
    if (capacity < 0) {
      throw new RangeError(`Capacity must be non-negative, got: ${capacity}`);
    }
    this.capacity = capacity;
    this.cache = new Map<string, T>();
  }

  get(key: string): T | undefined {
    if (key === undefined || key === null) {
      return undefined;
    }

    if (!this.cache.has(key)) {
      return undefined;
    }

    // Promote to most-recently-used by re-inserting at tail
    const value = this.cache.get(key) as T;
    this.cache.delete(key);
    this.cache.set(key, value);
    return value;
  }

  set(key: string, value: T): void {
    if (key === undefined || key === null) {
      throw new TypeError(`Cache key must be a non-null string, got: ${key}`);
    }

    // Zero-capacity cache holds nothing — short-circuit immediately
    if (this.capacity === 0) {
      return;
    }

    if (this.cache.has(key)) {
      // Update existing entry and promote to most-recently-used
      this.cache.delete(key);
      this.cache.set(key, value);
      return;
    }

    // Evict the least-recently-used entry (Map head) before inserting
    if (this.cache.size >= this.capacity) {
      const lruKey = this.cache.keys().next().value;
      if (lruKey !== undefined) {
        this.cache.delete(lruKey);
      }
    }

    this.cache.set(key, value);
  }
}

export default LRUCache;

type Primitive = string | number | boolean | null | undefined | bigint | symbol;
type NestedObject = { [key: string]: unknown };
type FlattenedObject = { [key: string]: Primitive };

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  input: unknown,
  maxDepth: number = 100
): FlattenedObject {
  if (input === null || input === undefined) return {};
  if (!isPlainObject(input)) {
    throw new TypeError(
      `Expected a plain object, received: ${Array.isArray(input) ? "array" : typeof input}`
    );
  }

  const result: FlattenedObject = {};

  function recurse(current: unknown, prefix: string, depth: number): void {
    if (depth > maxDepth) {
      throw new RangeError(
        `Maximum flattening depth of ${maxDepth} exceeded at key "${prefix}". Possible circular reference.`
      );
    }

    if (isPlainObject(current)) {
      const keys = Object.keys(current);

      if (keys.length === 0) {
        // Preserve empty objects as a key with undefined value only if they
        // appear as a nested value (prefix has been set).
        if (prefix !== "") {
          result[prefix] = undefined;
        }
        return;
      }

      for (const key of keys) {
        if (key === "") {
          // Empty-string keys would produce ambiguous dot-notation paths;
          // encode them with a sentinel so they round-trip unambiguously.
          const encodedKey = prefix === "" ? '[""]' : `${prefix}[""]`;
          recurse((current as NestedObject)[key], encodedKey, depth + 1);
        } else if (key.includes(".")) {
          // Keys containing dots are escaped with bracket notation to avoid
          // collisions with the dot-separated path separator.
          const encodedKey =
            prefix === "" ? `["${key}"]` : `${prefix}["${key}"]`;
          recurse((current as NestedObject)[key], encodedKey, depth + 1);
        } else {
          const nextKey = prefix === "" ? key : `${prefix}.${key}`;
          recurse((current as NestedObject)[key], nextKey, depth + 1);
        }
      }
    } else {
      // Leaf value — store it directly.
      result[prefix] = current as Primitive;
    }
  }

  recurse(input, "", 0);
  return result;
}

export default flattenObject;

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
  name: string;
}

const FIELD_CONFIGS: readonly [keyof CronFields, FieldConfig][] = [
  ["minute",     { min: 0,  max: 59, name: "minute" }],
  ["hour",       { min: 0,  max: 23, name: "hour" }],
  ["dayOfMonth", { min: 1,  max: 31, name: "dayOfMonth" }],
  ["month",      { min: 1,  max: 12, name: "month" }],
  ["dayOfWeek",  { min: 0,  max: 6,  name: "dayOfWeek" }],
];

class CronParseError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "CronParseError";
  }
}

function parseInteger(raw: string, fieldName: string): number {
  const trimmed = raw.trim();
  if (trimmed === "" || !/^\d+$/.test(trimmed)) {
    throw new CronParseError(
      `Invalid numeric value "${raw}" in field "${fieldName}"`
    );
  }
  const value = parseInt(trimmed, 10);
  if (!Number.isFinite(value)) {
    throw new CronParseError(
      `Non-finite numeric value "${raw}" in field "${fieldName}"`
    );
  }
  return value;
}

function assertInRange(value: number, config: FieldConfig): void {
  if (value < config.min || value > config.max) {
    throw new CronParseError(
      `Value ${value} is out of range [${config.min}-${config.max}] for field "${config.name}"`
    );
  }
}

function expandRange(start: number, end: number, config: FieldConfig): number[] {
  if (start > end) {
    throw new CronParseError(
      `Range start ${start} exceeds end ${end} in field "${config.name}"`
    );
  }
  assertInRange(start, config);
  assertInRange(end, config);
  const result: number[] = [];
  for (let i = start; i <= end; i++) {
    result.push(i);
  }
  return result;
}

function expandStep(base: string, step: number, config: FieldConfig): number[] {
  if (!Number.isFinite(step) || step < 1) {
    throw new CronParseError(
      `Step value must be a positive integer, got "${step}" in field "${config.name}"`
    );
  }

  let start: number;
  let end: number;

  if (base === "*") {
    start = config.min;
    end = config.max;
  } else if (/^\d+$/.test(base)) {
    start = parseInteger(base, config.name);
    assertInRange(start, config);
    end = config.max;
  } else if (/^\d+-\d+$/.test(base)) {
    const dashIndex = base.indexOf("-");
    start = parseInteger(base.slice(0, dashIndex), config.name);
    end = parseInteger(base.slice(dashIndex + 1), config.name);
    assertInRange(start, config);
    assertInRange(end, config);
    if (start > end) {
      throw new CronParseError(
        `Range start ${start} exceeds end ${end} in field "${config.name}"`
      );
    }
  } else {
    throw new CronParseError(
      `Invalid base expression "${base}" for step in field "${config.name}"`
    );
  }

  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function parseSegment(segment: string, config: FieldConfig): number[] {
  const trimmed = segment.trim();

  if (trimmed === "") {
    throw new CronParseError(
      `Empty segment encountered in field "${config.name}"`
    );
  }

  // Step expression: base/step
  if (trimmed.includes("/")) {
    const parts = trimmed.split("/");
    if (parts.length !== 2) {
      throw new CronParseError(
        `Invalid step expression "${trimmed}" in field "${config.name}"; expected exactly one "/"`
      );
    }
    const [base, stepStr] = parts;
    if (base.trim() === "" || stepStr.trim() === "") {
      throw new CronParseError(
        `Malformed step expression "${trimmed}" in field "${config.name}"`
      );
    }
    const step = parseInteger(stepStr.trim(), config.name);
    return expandStep(base.trim(), step, config);
  }

  // Wildcard
  if (trimmed === "*") {
    return expandRange(config.min, config.max, config);
  }

  // Range: start-end
  if (/^\d+-\d+$/.test(trimmed)) {
    const dashIndex = trimmed.indexOf("-");
    const start = parseInteger(trimmed.slice(0, dashIndex), config.name);
    const end = parseInteger(trimmed.slice(dashIndex + 1), config.name);
    return expandRange(start, end, config);
  }

  // Single integer
  if (/^\d+$/.test(trimmed)) {
    const value = parseInteger(trimmed, config.name);
    assertInRange(value, config);
    return [value];
  }

  throw new CronParseError(
    `Unrecognized segment "${trimmed}" in field "${config.name}"`
  );
}

function parseField(raw: string, config: FieldConfig): number[] {
  if (typeof raw !== "string") {
    throw new CronParseError(
      `Expected string for field "${config.name}", got ${typeof raw}`
    );
  }

  const trimmed = raw.trim();
  if (trimmed === "") {
    throw new CronParseError(`Field "${config.name}" must not be empty`);
  }

  const segments = trimmed.split(",");
  if (segments.length === 0) {
    throw new CronParseError(`Field "${config.name}" produced no segments`);
  }

  const valueSet = new Set<number>();
  for (const segment of segments) {
    const values = parseSegment(segment, config);
    for (const v of values) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new CronParseError(
      `parseCron expects a string argument, received ${typeof expression}`
    );
  }

  const normalized = expression.trim().replace(/\s+/g, " ");

  if (normalized === "") {
    throw new CronParseError("Cron expression must not be empty");
  }

  const parts = normalized.split(" ");

  if (parts.length !== 5) {
    throw new CronParseError(
      `Cron expression must have exactly 5 fields, got ${parts.length}: "${expression}"`
    );
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_CONFIGS.length; i++) {
    const [fieldKey, config] = FIELD_CONFIGS[i];
    result[fieldKey] = parseField(parts[i], config);
  }

  return result;
}

export default parseCron;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldRange {
  min: number;
  max: number;
}

const FIELD_RANGES: Record<CronField, FieldRange> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
};

const FIELD_ORDER: CronField[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function clampDayOfWeek(values: number[]): number[] {
  // Sunday can be represented as 0 or 7; normalize 7 → 0 and deduplicate
  const normalized = values.map((v) => (v === 7 ? 0 : v));
  return [...new Set(normalized)].sort((a, b) => a - b);
}

function assertInRange(value: number, field: CronField): void {
  const { min, max } = FIELD_RANGES[field];
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of range [${min}, ${max}] for field "${field}"`
    );
  }
}

function parseInteger(raw: string, field: CronField): number {
  const trimmed = raw.trim();
  if (!/^\d+$/.test(trimmed)) {
    throw new SyntaxError(
      `Invalid numeric token "${trimmed}" in field "${field}"`
    );
  }
  const value = parseInt(trimmed, 10);
  assertInRange(value, field);
  return value;
}

function expandRange(start: number, end: number, field: CronField): number[] {
  if (start > end) {
    throw new RangeError(
      `Range start ${start} is greater than end ${end} in field "${field}"`
    );
  }
  const values: number[] = [];
  for (let i = start; i <= end; i++) {
    values.push(i);
  }
  return values;
}

function parseSegment(segment: string, field: CronField): number[] {
  const trimmed = segment.trim();

  if (!trimmed) {
    throw new SyntaxError(`Empty segment in field "${field}"`);
  }

  const { min, max } = FIELD_RANGES[field];

  // Step value: */step or range/step
  if (trimmed.includes("/")) {
    const slashParts = trimmed.split("/");
    if (slashParts.length !== 2) {
      throw new SyntaxError(
        `Invalid step expression "${trimmed}" in field "${field}"`
      );
    }

    const [rangePart, stepPart] = slashParts;
    const stepStr = stepPart.trim();

    if (!/^\d+$/.test(stepStr)) {
      throw new SyntaxError(
        `Invalid step value "${stepStr}" in field "${field}"`
      );
    }

    const step = parseInt(stepStr, 10);
    if (step <= 0) {
      throw new RangeError(
        `Step value must be >= 1, got ${step} in field "${field}"`
      );
    }

    let rangeStart = min;
    let rangeEnd = max;

    const rangePartTrimmed = rangePart.trim();
    if (rangePartTrimmed !== "*") {
      if (rangePartTrimmed.includes("-")) {
        const dashParts = rangePartTrimmed.split("-");
        if (dashParts.length !== 2) {
          throw new SyntaxError(
            `Invalid range "${rangePartTrimmed}" in field "${field}"`
          );
        }
        rangeStart = parseInteger(dashParts[0], field);
        rangeEnd = parseInteger(dashParts[1], field);
        if (rangeStart > rangeEnd) {
          throw new RangeError(
            `Range start ${rangeStart} > end ${rangeEnd} in field "${field}"`
          );
        }
      } else {
        rangeStart = parseInteger(rangePartTrimmed, field);
        rangeEnd = max;
      }
    }

    const values: number[] = [];
    for (let i = rangeStart; i <= rangeEnd; i += step) {
      values.push(i);
    }
    return values;
  }

  // Wildcard
  if (trimmed === "*") {
    return expandRange(min, max, field);
  }

  // Range: start-end
  if (trimmed.includes("-")) {
    const dashParts = trimmed.split("-");
    if (dashParts.length !== 2) {
      throw new SyntaxError(
        `Invalid range expression "${trimmed}" in field "${field}"`
      );
    }
    const start = parseInteger(dashParts[0], field);
    const end = parseInteger(dashParts[1], field);
    return expandRange(start, end, field);
  }

  // Plain number
  const value = parseInteger(trimmed, field);
  return [value];
}

function parseField(expression: string, field: CronField): number[] {
  if (typeof expression !== "string") {
    throw new TypeError(`Field "${field}" must be a string`);
  }

  const trimmed = expression.trim();
  if (!trimmed) {
    throw new SyntaxError(`Field "${field}" expression is empty`);
  }

  const segments = trimmed.split(",");
  if (segments.length === 0) {
    throw new SyntaxError(`Field "${field}" has no segments`);
  }

  const valueSet = new Set<number>();
  for (const segment of segments) {
    const values = parseSegment(segment, field);
    for (const v of values) {
      valueSet.add(v);
    }
  }

  let sorted = [...valueSet].sort((a, b) => a - b);

  if (field === "dayOfWeek") {
    sorted = clampDayOfWeek(sorted);
  }

  return sorted;
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError(
      `parseCron expects a string, received ${typeof expression}`
    );
  }

  const trimmed = expression.trim();
  if (!trimmed) {
    throw new SyntaxError("Cron expression must not be empty");
  }

  // Split on whitespace, collapsing multiple spaces/tabs
  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as CronResult;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    result[fieldName] = parseField(fields[i], fieldName);
  }

  return result;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] };
type FlatObject = { [key: string]: Primitive | unknown[] };

function flattenObject(
  input: unknown,
  prefix: string = "",
  result: FlatObject = {},
  seen: WeakSet<object> = new WeakSet()
): FlatObject {
  if (input === null || input === undefined) {
    if (prefix) result[prefix] = input as Primitive;
    return result;
  }

  if (typeof input !== "object" || Array.isArray(input)) {
    if (prefix) result[prefix] = input as Primitive | unknown[];
    return result;
  }

  const obj = input as Record<string, unknown>;

  if (seen.has(obj)) {
    throw new TypeError(`Circular reference detected at key: "${prefix}"`);
  }
  seen.add(obj);

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {} as unknown as Primitive;
    return result;
  }

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    const sanitizedKey = String(key);
    const newPrefix = prefix ? `${prefix}.${sanitizedKey}` : sanitizedKey;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value, newPrefix, result, seen);
    } else {
      result[newPrefix] = value as Primitive | unknown[];
    }
  }

  seen.delete(obj);

  return result;
}

export default flattenObject;

interface DLLNode<T> {
  key: string;
  value: T;
  prev: DLLNode<T> | null;
  next: DLLNode<T> | null;
}

class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, DLLNode<T>>;
  // Sentinel nodes: head.next = MRU, tail.prev = LRU
  private readonly head: DLLNode<T>;
  private readonly tail: DLLNode<T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 0) {
      throw new RangeError(
        `LRUCache capacity must be a non-negative integer, got: ${capacity}`
      );
    }
    this.capacity = capacity;
    this.map = new Map();
    this.head = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.tail = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key: string): T | undefined {
    const node = this.map.get(key);
    if (node === undefined) return undefined;
    this.moveToFront(node);
    return node.value;
  }

  set(key: string, value: T): void {
    // A zero-capacity cache cannot store anything — all sets are no-ops.
    if (this.capacity === 0) return;

    const existing = this.map.get(key);
    if (existing !== undefined) {
      existing.value = value;
      this.moveToFront(existing);
      return;
    }

    // Evict before inserting so map.size never transiently exceeds capacity.
    if (this.map.size >= this.capacity) {
      this.evictLRU();
    }

    const node: DLLNode<T> = { key, value, prev: null, next: null };
    this.map.set(key, node);
    this.insertAtFront(node);
  }

  // ─── Private helpers ──────────────────────────────────────────────────────

  private insertAtFront(node: DLLNode<T>): void {
    // Wire node between head sentinel and current MRU.
    const mru = this.head.next!;
    node.prev = this.head;
    node.next = mru;
    mru.prev = node;
    this.head.next = node;
  }

  private removeNode(node: DLLNode<T>): void {
    const prev = node.prev!;
    const next = node.next!;
    prev.next = next;
    next.prev = prev;
    // Null out pointers to prevent accidental stale references.
    node.prev = null;
    node.next = null;
  }

  private moveToFront(node: DLLNode<T>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  private evictLRU(): void {
    const lru = this.tail.prev!;
    // Guard: if the list is logically empty, the LRU candidate is the head sentinel.
    if (lru === this.head) return;
    this.removeNode(lru);
    this.map.delete(lru.key);
  }
}

export default LRUCache;

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

export class CronParseError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "CronParseError";
  }
}

interface FieldRange {
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: ReadonlyArray<{
  name: keyof CronExpression;
  range: FieldRange;
}> = [
  { name: "minute", range: { min: 0, max: 59 } },
  { name: "hour", range: { min: 0, max: 23 } },
  { name: "dayOfMonth", range: { min: 1, max: 31 } },
  { name: "month", range: { min: 1, max: 12 } },
  { name: "dayOfWeek", range: { min: 0, max: 7 } }, // 7 is a Sunday alias in standard cron
] as const;

/** Returns true only if the string is a non-empty sequence of ASCII digits. */
function isNonNegativeInteger(value: string): boolean {
  return value.length > 0 && /^\d+$/.test(value);
}

function parseNonNegativeInteger(value: string, context: string): number {
  if (!isNonNegativeInteger(value)) {
    throw new CronParseError(
      `Invalid integer "${value}" in field "${context}"`
    );
  }
  return parseInt(value, 10);
}

function assertInRange(
  value: number,
  range: FieldRange,
  fieldName: string
): void {
  if (value < range.min || value > range.max) {
    throw new CronParseError(
      `Value ${value} is out of range [${range.min}–${range.max}] for field "${fieldName}"`
    );
  }
}

function buildRange(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) {
    result.push(i);
  }
  return result;
}

function buildStep(
  start: number,
  end: number,
  step: number,
  fieldName: string
): number[] {
  if (step <= 0) {
    throw new CronParseError(
      `Step value must be a positive integer, got ${step} in field "${fieldName}"`
    );
  }
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

/**
 * Parses a single non-comma segment such as "*", "5", "1-5", "*/15",
 * "1-5/2", or "0/10".
 */
function parseSegment(
  segment: string,
  range: FieldRange,
  fieldName: string
): number[] {
  if (segment === "") {
    throw new CronParseError(
      `Empty segment encountered in field "${fieldName}"`
    );
  }

  // ── Step notation (/): "*/n", "start/n", "start-end/n" ──────────────────
  const slashIdx = segment.indexOf("/");
  if (slashIdx !== -1) {
    const baseStr = segment.substring(0, slashIdx);
    const stepStr = segment.substring(slashIdx + 1);

    if (baseStr === "") {
      throw new CronParseError(
        `Missing base before "/" in segment "${segment}" for field "${fieldName}"`
      );
    }
    if (stepStr === "") {
      throw new CronParseError(
        `Missing step after "/" in segment "${segment}" for field "${fieldName}"`
      );
    }

    const step = parseNonNegativeInteger(stepStr, fieldName);
    if (step === 0) {
      throw new CronParseError(
        `Step value must be positive (got 0) in field "${fieldName}"`
      );
    }

    let start: number;
    let end: number;

    if (baseStr === "*") {
      start = range.min;
      end = range.max;
    } else if (baseStr.includes("-")) {
      const dashIdx = baseStr.indexOf("-");
      start = parseNonNegativeInteger(baseStr.substring(0, dashIdx), fieldName);
      end = parseNonNegativeInteger(baseStr.substring(dashIdx + 1), fieldName);
      assertInRange(start, range, fieldName);
      assertInRange(end, range, fieldName);
      if (start > end) {
        throw new CronParseError(
          `Range start ${start} exceeds end ${end} in field "${fieldName}"`
        );
      }
    } else {
      start = parseNonNegativeInteger(baseStr, fieldName);
      assertInRange(start, range, fieldName);
      end = range.max;
    }

    return buildStep(start, end, step, fieldName);
  }

  // ── Wildcard ─────────────────────────────────────────────────────────────
  if (segment === "*") {
    return buildRange(range.min, range.max);
  }

  // ── Range notation: "start-end" ──────────────────────────────────────────
  const dashIdx = segment.indexOf("-");
  if (dashIdx !== -1) {
    const startStr = segment.substring(0, dashIdx);
    const endStr = segment.substring(dashIdx + 1);

    if (startStr === "" || endStr === "") {
      throw new CronParseError(
        `Malformed range "${segment}" in field "${fieldName}"`
      );
    }

    const start = parseNonNegativeInteger(startStr, fieldName);
    const end = parseNonNegativeInteger(endStr, fieldName);

    assertInRange(start, range, fieldName);
    assertInRange(end, range, fieldName);

    if (start > end) {
      throw new CronParseError(
        `Range start ${start} exceeds end ${end} in field "${fieldName}"`
      );
    }

    return buildRange(start, end);
  }

  // ── Single numeric value ─────────────────────────────────────────────────
  const value = parseNonNegativeInteger(segment, fieldName);
  assertInRange(value, range, fieldName);
  return [value];
}

/**
 * Parses a full cron field string, which may be a comma-separated list of
 * segments, and returns a sorted, deduplicated array of concrete values.
 */
function parseField(
  raw: string,
  range: FieldRange,
  fieldName: string
): number[] {
  const trimmed = raw.trim();
  if (trimmed === "") {
    throw new CronParseError(`Field "${fieldName}" must not be empty`);
  }

  const parts = trimmed.split(",");
  const valueSet = new Set<number>();

  for (const part of parts) {
    const segment = part.trim();
    if (segment === "") {
      throw new CronParseError(
        `Trailing or consecutive comma in field "${fieldName}"`
      );
    }
    for (const v of parseSegment(segment, range, fieldName)) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

/**
 * Parses a standard 5-field cron expression string into a structured object
 * whose properties each contain a sorted array of every concrete value that
 * field matches.
 *
 * Supported per-field syntax:
 *   *         – every value in the field's valid range
 *   n         – exact value
 *   n-m       – inclusive range
 *   */step    – every `step` values across the full range
 *   n/step    – every `step` values starting from n
 *   n-m/step  – every `step` values within n–m
 *   a,b,c     – comma-separated combination of any of the above
 *
 * Valid ranges:
 *   minute:     0–59
 *   hour:       0–23
 *   dayOfMonth: 1–31
 *   month:      1–12
 *   dayOfWeek:  0–7  (0 and 7 both represent Sunday)
 *
 * @throws {CronParseError} on any validation or parse failure
 */
export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new CronParseError(
      `parseCron expects a string, received ${typeof expression}`
    );
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new CronParseError("Cron expression must not be empty");
  }

  const rawFields = trimmed.split(/\s+/);
  if (rawFields.length !== 5) {
    throw new CronParseError(
      `Expected exactly 5 whitespace-separated fields, got ${rawFields.length}: "${trimmed}"`
    );
  }

  const result = {} as CronExpression;

  for (let i = 0; i < FIELD_CONFIGS.length; i++) {
    const { name, range } = FIELD_CONFIGS[i];
    result[name] = parseField(rawFields[i], range, name);
  }

  return result;
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  if (value instanceof Date) return false;
  if (value instanceof RegExp) return false;
  if (value instanceof Map) return false;
  if (value instanceof Set) return false;
  if (Array.isArray(value)) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObjectInternal(
  obj: PlainObject,
  prefix: string,
  result: PlainObject,
  seen: WeakSet<PlainObject>
): void {
  if (seen.has(obj)) {
    throw new TypeError(
      `Circular reference detected at key: "${prefix || "(root)"}"`
    );
  }

  seen.add(obj);

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    // Empty object — preserve it as a leaf so no data is silently lost
    if (prefix !== "") {
      result[prefix] = obj;
    }
    seen.delete(obj);
    return;
  }

  for (const key of keys) {
    // Guard against prototype-polluting keys (shouldn't reach here via
    // Object.keys, but be explicit about our intent)
    if (key === "__proto__" || key === "constructor" || key === "prototype") {
      continue;
    }

    const value: unknown = obj[key];
    const newKey = prefix !== "" ? `${prefix}.${key}` : key;

    if (isPlainObject(value) && Object.keys(value).length > 0) {
      flattenObjectInternal(value, newKey, result, seen);
    } else {
      result[newKey] = value;
    }
  }

  // Remove after processing so sibling/cousin references to the same object
  // (non-circular DAG shapes) are handled correctly rather than throwing.
  seen.delete(obj);
}

export default function flattenObject(obj: unknown): PlainObject {
  if (!isPlainObject(obj)) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${
        obj === null ? "null" : Array.isArray(obj) ? "array" : typeof obj
      }`
    );
  }

  const result: PlainObject = {};
  flattenObjectInternal(obj, "", result, new WeakSet());
  return result;
}

export interface ParsedCron {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type CronField = keyof ParsedCron;

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 6 },
};

const FIELD_ORDER: CronField[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

const isDigitString = (s: string): boolean => /^\d+$/.test(s);

function assertInRange(
  value: number,
  min: number,
  max: number,
  context: string
): void {
  if (value < min || value > max) {
    throw new RangeError(
      `${context}: ${value} is outside valid range [${min}, ${max}]`
    );
  }
}

function parseStepExpression(
  token: string,
  field: CronField
): number[] {
  const { min, max } = FIELD_RANGES[field];
  const slashIndex = token.indexOf("/");
  const left = token.slice(0, slashIndex);
  const stepStr = token.slice(slashIndex + 1);

  if (!isDigitString(stepStr)) {
    throw new SyntaxError(
      `Field "${field}": invalid step value "${stepStr}" in "${token}"`
    );
  }

  const step = parseInt(stepStr, 10);

  if (step <= 0) {
    throw new RangeError(
      `Field "${field}": step must be a positive integer, got ${step}`
    );
  }

  let rangeMin: number;
  let rangeMax: number;

  if (left === "*") {
    rangeMin = min;
    rangeMax = max;
  } else if (left.includes("-")) {
    [rangeMin, rangeMax] = parseRangeBounds(left, field);
  } else if (isDigitString(left) && left.length > 0) {
    rangeMin = parseInt(left, 10);
    assertInRange(rangeMin, min, max, `Field "${field}" step start`);
    rangeMax = max;
  } else {
    throw new SyntaxError(
      `Field "${field}": invalid step expression "${token}"`
    );
  }

  const values: number[] = [];
  for (let v = rangeMin; v <= rangeMax; v += step) {
    values.push(v);
  }

  if (values.length === 0) {
    throw new RangeError(
      `Field "${field}": step expression "${token}" produces no valid values`
    );
  }

  return values;
}

function parseRangeBounds(token: string, field: CronField): [number, number] {
  const { min, max } = FIELD_RANGES[field];
  const dashIndex = token.indexOf("-");

  if (dashIndex <= 0) {
    throw new SyntaxError(
      `Field "${field}": invalid range expression "${token}"`
    );
  }

  const startStr = token.slice(0, dashIndex);
  const endStr = token.slice(dashIndex + 1);

  if (!isDigitString(startStr) || !isDigitString(endStr)) {
    throw new SyntaxError(
      `Field "${field}": non-integer bounds in range "${token}"`
    );
  }

  const start = parseInt(startStr, 10);
  const end = parseInt(endStr, 10);

  assertInRange(start, min, max, `Field "${field}" range start`);
  assertInRange(end, min, max, `Field "${field}" range end`);

  if (start > end) {
    throw new RangeError(
      `Field "${field}": range start ${start} must not exceed range end ${end} in "${token}"`
    );
  }

  return [start, end];
}

function parseField(token: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];

  if (token === "" || token == null) {
    throw new SyntaxError(`Field "${field}" token is empty or missing`);
  }

  // Wildcard — expand to full valid range
  if (token === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => i + min);
  }

  // Step expression: */n or start/n or start-end/n
  if (token.includes("/")) {
    const slashCount = (token.match(/\//g) ?? []).length;
    if (slashCount > 1) {
      throw new SyntaxError(
        `Field "${field}": multiple "/" characters in "${token}"`
      );
    }
    return parseStepExpression(token, field);
  }

  // Comma-separated list of integers (no nested ranges or steps)
  if (token.includes(",")) {
    const parts = token.split(",");
    const seen = new Set<number>();
    const values: number[] = [];

    for (const part of parts) {
      if (part === "") {
        throw new SyntaxError(
          `Field "${field}": empty element in comma-separated list "${token}"`
        );
      }
      if (!isDigitString(part)) {
        throw new SyntaxError(
          `Field "${field}": non-integer value "${part}" in list "${token}"`
        );
      }
      const num = parseInt(part, 10);
      assertInRange(num, min, max, `Field "${field}" list value`);
      if (!seen.has(num)) {
        seen.add(num);
        values.push(num);
      }
    }

    return values.sort((a, b) => a - b);
  }

  // Range: n-m
  if (token.includes("-")) {
    const [start, end] = parseRangeBounds(token, field);
    return Array.from({ length: end - start + 1 }, (_, i) => i + start);
  }

  // Single integer
  if (!isDigitString(token)) {
    throw new SyntaxError(
      `Field "${field}": unrecognized token "${token}"`
    );
  }

  const num = parseInt(token, 10);
  assertInRange(num, min, max, `Field "${field}"`);
  return [num];
}

export default function parseCron(expression: string): ParsedCron {
  if (typeof expression !== "string") {
    throw new TypeError(
      `parseCron requires a string argument, received ${typeof expression}`
    );
  }

  const trimmed = expression.trim();

  if (trimmed.length === 0) {
    throw new SyntaxError("Cron expression must not be empty");
  }

  const tokens = trimmed.split(/\s+/);

  if (tokens.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek), ` +
        `got ${tokens.length} in: "${expression}"`
    );
  }

  const result = {} as ParsedCron;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const field = FIELD_ORDER[i];
    // Guard: token should always exist given the length check above, but be explicit
    const token = tokens[i];
    if (token === undefined) {
      throw new SyntaxError(`Field "${field}" is missing from the expression`);
    }
    result[field] = parseField(token, field);
  }

  return result;
}

type Primitive = string | number | boolean | null | undefined | symbol | bigint | Function;

type NestedObject = {
  [key: string]: Primitive | NestedObject | NestedObject[] | unknown;
};

type FlatObject = Record<string, unknown>;

function isPlainObjectOrArray(value: unknown): value is Record<string, unknown> | unknown[] {
  if (value === null || value === undefined) return false;
  if (typeof value !== "object") return false;
  // Treat built-in non-plain objects (Date, RegExp, Map, Set, etc.) as leaf values
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === Array.prototype;
}

function flattenObject(
  input: unknown,
  prefix: string = "",
  result: FlatObject = {},
  seen: WeakSet<object> = new WeakSet()
): FlatObject {
  if (input === null || input === undefined || typeof input !== "object") {
    if (prefix !== "") result[prefix] = input;
    return result;
  }

  // Guard against circular references — this WILL cause infinite recursion without it
  if (seen.has(input as object)) {
    if (prefix !== "") result[prefix] = "[Circular]";
    return result;
  }
  seen.add(input as object);

  if (!isPlainObjectOrArray(input)) {
    // Non-plain object (Date, RegExp, Map, Set, etc.) — treat as leaf
    if (prefix !== "") result[prefix] = input;
    seen.delete(input as object);
    return result;
  }

  const entries = Array.isArray(input)
    ? (input as unknown[]).map((v, i) => [String(i), v] as [string, unknown])
    : Object.entries(input as Record<string, unknown>);

  // An empty object/array at a nested path would silently vanish — preserve it
  if (entries.length === 0) {
    if (prefix !== "") result[prefix] = input;
    seen.delete(input as object);
    return result;
  }

  for (const [key, value] of entries) {
    // Reject keys containing dots to avoid ambiguous round-trips
    const safeKey = key.includes(".") ? key.replace(/\./g, "\\.") : key;
    const newPrefix = prefix === "" ? safeKey : `${prefix}.${safeKey}`;
    flattenObject(value, newPrefix, result, seen);
  }

  seen.delete(input as object);
  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined | bigint | symbol;
type NestedRecord = { [key: string]: unknown };
type FlattenedRecord = Record<string, Primitive>;

const UNSAFE_KEYS = new Set(["__proto__", "constructor", "prototype"]);

function isPlainObject(value: unknown): value is NestedRecord {
  if (value === null || typeof value !== "object" || Array.isArray(value)) {
    return false;
  }
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  input: NestedRecord | unknown[],
  prefix = "",
  seen = new WeakSet<object>()
): FlattenedRecord {
  if (input === null || (typeof input !== "object" && !Array.isArray(input))) {
    throw new TypeError(
      `flattenObject: expected a non-null object or array, got ${input === null ? "null" : typeof input}`
    );
  }

  if (seen.has(input as object)) {
    throw new RangeError(
      `flattenObject: circular reference detected at path "${prefix}"`
    );
  }

  seen.add(input as object);

  const result: FlattenedRecord = {};
  const entries = Array.isArray(input)
    ? input.map((v, i) => [String(i), v] as [string, unknown])
    : Object.entries(input);

  for (const [key, value] of entries) {
    if (UNSAFE_KEYS.has(key)) {
      continue;
    }

    const fullKey = prefix.length > 0 ? `${prefix}.${key}` : key;

    if (isPlainObject(value)) {
      const nested = flattenObject(value, fullKey, seen);
      const nestedKeys = Object.keys(nested);
      if (nestedKeys.length === 0) {
        // Preserve empty object as explicit null rather than silently dropping
        result[fullKey] = null;
      } else {
        for (const k of nestedKeys) {
          result[k] = nested[k];
        }
      }
    } else if (Array.isArray(value)) {
      if (value.length === 0) {
        result[fullKey] = null;
      } else {
        const nested = flattenObject(value, fullKey, seen);
        for (const k of Object.keys(nested)) {
          result[k] = nested[k];
        }
      }
    } else {
      // Leaf value: primitives, Date, RegExp, Map, Set, functions, etc.
      result[fullKey] = value as Primitive;
    }
  }

  seen.delete(input as object);

  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined | bigint | symbol;

type NestedObject = {
  [key: string]: Primitive | NestedObject | unknown[] | unknown;
};

type FlattenedObject = Record<string, Primitive>;

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  input: unknown,
  options: {
    delimiter?: string;
    maxDepth?: number;
    preserveArrays?: boolean;
  } = {}
): FlattenedObject {
  const { delimiter = ".", maxDepth = Infinity, preserveArrays = false } =
    options;

  if (delimiter === "") {
    throw new Error("Delimiter must be a non-empty string.");
  }

  if (typeof maxDepth !== "number" || maxDepth < 1) {
    throw new Error("maxDepth must be a positive number.");
  }

  if (!isPlainObject(input) && !Array.isArray(input)) {
    throw new TypeError(
      `Input must be a plain object or array, received: ${
        input === null ? "null" : typeof input
      }`
    );
  }

  const result: FlattenedObject = {};
  const seen = new WeakSet<object>();

  function recurse(
    current: unknown,
    prefix: string,
    depth: number
  ): void {
    if (
      isPlainObject(current) ||
      (!preserveArrays && Array.isArray(current))
    ) {
      const obj = current as object;

      if (seen.has(obj)) {
        throw new Error(
          `Circular reference detected at key: "${prefix || "(root)"}"`
        );
      }

      const entries = isPlainObject(current)
        ? Object.entries(current as NestedObject)
        : (current as unknown[]).map<[string, unknown]>((v, i) => [
            String(i),
            v,
          ]);

      if (entries.length === 0) {
        if (prefix !== "") {
          (result as Record<string, unknown>)[prefix] = current;
        }
        return;
      }

      if (depth >= maxDepth) {
        if (prefix !== "") {
          (result as Record<string, unknown>)[prefix] = current;
        }
        return;
      }

      seen.add(obj);

      for (const [key, value] of entries) {
        if (key === "") {
          throw new Error("Object keys must be non-empty strings.");
        }
        if (key.includes(delimiter)) {
          throw new Error(
            `Key "${key}" contains the delimiter "${delimiter}". ` +
              `This would produce ambiguous flattened output.`
          );
        }

        const newKey = prefix === "" ? key : `${prefix}${delimiter}${key}`;
        recurse(value, newKey, depth + 1);
      }

      seen.delete(obj);
    } else {
      if (prefix !== "") {
        (result as Record<string, unknown>)[prefix] = current;
      }
    }
  }

  recurse(input, "", 0);
  return result;
}

export default flattenObject;

interface Node<T> {
  key: string;
  value: T;
  prev: Node<T> | null;
  next: Node<T> | null;
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;
  private readonly head: Node<T>;
  private readonly tail: Node<T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 1) {
      throw new RangeError(`Capacity must be a positive integer, got: ${capacity}`);
    }

    this.capacity = capacity;
    this.map = new Map();

    this.head = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.tail = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key: string): T | undefined {
    if (typeof key !== "string") return undefined;

    const node = this.map.get(key);
    if (node === undefined) return undefined;

    this.moveToFront(node);
    return node.value;
  }

  set(key: string, value: T): void {
    if (typeof key !== "string") {
      throw new TypeError(`Key must be a string, got: ${typeof key}`);
    }

    const existing = this.map.get(key);

    if (existing !== undefined) {
      existing.value = value;
      this.moveToFront(existing);
      return;
    }

    if (this.map.size >= this.capacity) {
      this.evictLRU();
    }

    const node: Node<T> = { key, value, prev: null, next: null };
    this.map.set(key, node);
    this.insertAtFront(node);
  }

  get size(): number {
    return this.map.size;
  }

  has(key: string): boolean {
    return typeof key === "string" && this.map.has(key);
  }

  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  private insertAtFront(node: Node<T>): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  private removeNode(node: Node<T>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    node.prev = null;
    node.next = null;
  }

  private moveToFront(node: Node<T>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  private evictLRU(): void {
    const lru = this.tail.prev;
    if (lru === null || lru === this.head) return;

    this.removeNode(lru);
    this.map.delete(lru.key);
  }
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly name: keyof CronFields;
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute",     min: 0,  max: 59 },
  { name: "hour",       min: 0,  max: 23 },
  { name: "dayOfMonth", min: 1,  max: 31 },
  { name: "month",      min: 1,  max: 12 },
  { name: "dayOfWeek",  min: 0,  max: 7  },
] as const;

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of valid range [${min}–${max}] in field "${context}"`
    );
  }
}

function assertPositiveStep(step: number, context: string): void {
  if (!Number.isInteger(step) || step <= 0) {
    throw new RangeError(`Step value must be a positive integer in field "${context}", got ${step}`);
  }
}

function expandRange(start: number, end: number, step: number): number[] {
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

/**
 * Parses a single token within a cron field segment.
 * Supported forms: *, *\/n, n, n-m, n-m\/s
 */
function parseToken(token: string, min: number, max: number, fieldName: string): number[] {
  // Wildcard: *
  if (token === "*") {
    return expandRange(min, max, 1);
  }

  // Step on wildcard: */n
  const stepWildcard = /^\*\/(\d+)$/.exec(token);
  if (stepWildcard) {
    const step = parseInt(stepWildcard[1], 10);
    assertPositiveStep(step, fieldName);
    return expandRange(min, max, step);
  }

  // Range with optional step: n-m or n-m/s
  const rangePattern = /^(\d+)-(\d+)(?:\/(\d+))?$/.exec(token);
  if (rangePattern) {
    const start = parseInt(rangePattern[1], 10);
    const end   = parseInt(rangePattern[2], 10);
    const step  = rangePattern[3] !== undefined ? parseInt(rangePattern[3], 10) : 1;

    assertInRange(start, min, max, fieldName);
    assertInRange(end,   min, max, fieldName);
    assertPositiveStep(step, fieldName);

    if (start > end) {
      throw new RangeError(
        `Range start (${start}) must not exceed range end (${end}) in field "${fieldName}"`
      );
    }

    return expandRange(start, end, step);
  }

  // Plain integer: n
  const intPattern = /^(\d+)$/.exec(token);
  if (intPattern) {
    const value = parseInt(intPattern[1], 10);
    assertInRange(value, min, max, fieldName);
    return [value];
  }

  throw new SyntaxError(`Unrecognized token "${token}" in field "${fieldName}"`);
}

/**
 * Parses a single cron field (which may be comma-separated) into a sorted,
 * deduplicated array of numeric values.
 */
function parseField(raw: string, config: FieldConfig): number[] {
  if (typeof raw !== "string" || raw.trim().length === 0) {
    throw new TypeError(`Field "${config.name}" must be a non-empty string`);
  }

  const segments = raw.split(",");
  const valueSet = new Set<number>();

  for (const segment of segments) {
    const trimmed = segment.trim();
    if (trimmed.length === 0) {
      throw new SyntaxError(`Empty segment in field "${config.name}" (check for trailing commas)`);
    }

    const values = parseToken(trimmed, config.min, config.max, config.name);
    for (const v of values) {
      valueSet.add(v);
    }
  }

  if (valueSet.size === 0) {
    throw new RangeError(`Field "${config.name}" resolved to an empty set of values`);
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

/**
 * Parses a simplified 5-field cron expression into a structured object whose
 * values are sorted arrays of all matching integers for each field.
 *
 * Field order: minute  hour  dayOfMonth  month  dayOfWeek
 * Valid ranges:  0-59   0-23    1-31      1-12     0-7
 *
 * Each field supports: *, *\/n, n, n-m, n-m\/s, or comma-separated combinations.
 *
 * @throws {TypeError}   if the expression is not a string or has the wrong field count
 * @throws {SyntaxError} if a field token cannot be parsed
 * @throws {RangeError}  if a numeric value falls outside the field's valid range
 */
export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, received ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed.length === 0) {
    throw new TypeError("Cron expression must not be an empty or whitespace-only string");
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new TypeError(
      `Cron expression must contain exactly 5 whitespace-separated fields, got ${fields.length}: "${trimmed}"`
    );
  }

  return {
    minute:     parseField(fields[0], FIELD_CONFIGS[0]),
    hour:       parseField(fields[1], FIELD_CONFIGS[1]),
    dayOfMonth: parseField(fields[2], FIELD_CONFIGS[2]),
    month:      parseField(fields[3], FIELD_CONFIGS[3]),
    dayOfWeek:  parseField(fields[4], FIELD_CONFIGS[4]),
  };
}

interface Node<T> {
  key: string;
  value: T;
  prev: Node<T> | null;
  next: Node<T> | null;
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;
  private readonly head: Node<T>;
  private readonly tail: Node<T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity <= 0) {
      throw new RangeError(`LRUCache capacity must be a positive integer, got: ${capacity}`);
    }

    this.capacity = capacity;
    this.map = new Map();

    this.head = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.tail = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key: string): T | undefined {
    if (typeof key !== "string") return undefined;

    const node = this.map.get(key);
    if (node === undefined) return undefined;

    this.moveToFront(node);
    return node.value;
  }

  set(key: string, value: T): void {
    if (typeof key !== "string") {
      throw new TypeError(`LRUCache key must be a string, got: ${typeof key}`);
    }

    const existing = this.map.get(key);

    if (existing !== undefined) {
      existing.value = value;
      this.moveToFront(existing);
      return;
    }

    if (this.map.size >= this.capacity) {
      this.evictLRU();
    }

    const node: Node<T> = { key, value, prev: null, next: null };
    this.map.set(key, node);
    this.insertAtFront(node);
  }

  get size(): number {
    return this.map.size;
  }

  has(key: string): boolean {
    if (typeof key !== "string") return false;
    return this.map.has(key);
  }

  delete(key: string): boolean {
    if (typeof key !== "string") return false;

    const node = this.map.get(key);
    if (node === undefined) return false;

    this.removeNode(node);
    this.map.delete(key);
    return true;
  }

  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  private insertAtFront(node: Node<T>): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  private removeNode(node: Node<T>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    node.prev = null;
    node.next = null;
  }

  private moveToFront(node: Node<T>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  private evictLRU(): void {
    const lru = this.tail.prev;
    if (lru === null || lru === this.head) return;
    this.removeNode(lru);
    this.map.delete(lru.key);
  }
}

interface Node<T> {
  key: string;
  value: T;
  prev: Node<T> | null;
  next: Node<T> | null;
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;
  private readonly head: Node<T>;
  private readonly tail: Node<T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 1) {
      throw new RangeError(`Capacity must be a positive integer, got: ${capacity}`);
    }

    this.capacity = capacity;
    this.map = new Map();

    this.head = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.tail = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key: string): T | undefined {
    if (typeof key !== "string") {
      return undefined;
    }

    const node = this.map.get(key);
    if (node === undefined) {
      return undefined;
    }

    this.moveToFront(node);
    return node.value;
  }

  set(key: string, value: T): void {
    if (typeof key !== "string") {
      throw new TypeError(`Cache key must be a string, got: ${typeof key}`);
    }

    if (value === undefined) {
      throw new TypeError("Cache value must not be undefined");
    }

    const existing = this.map.get(key);

    if (existing !== undefined) {
      existing.value = value;
      this.moveToFront(existing);
      return;
    }

    if (this.map.size >= this.capacity) {
      this.evictLRU();
    }

    const node: Node<T> = { key, value, prev: null, next: null };
    this.map.set(key, node);
    this.insertAtFront(node);
  }

  get size(): number {
    return this.map.size;
  }

  has(key: string): boolean {
    return typeof key === "string" && this.map.has(key);
  }

  delete(key: string): boolean {
    if (typeof key !== "string") {
      return false;
    }

    const node = this.map.get(key);
    if (node === undefined) {
      return false;
    }

    this.removeNode(node);
    this.map.delete(key);
    return true;
  }

  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  private insertAtFront(node: Node<T>): void {
    node.prev = this.head;
    node.next = this.head.next;

    if (this.head.next !== null) {
      this.head.next.prev = node;
    }

    this.head.next = node;
  }

  private removeNode(node: Node<T>): void {
    if (node.prev !== null) {
      node.prev.next = node.next;
    }

    if (node.next !== null) {
      node.next.prev = node.prev;
    }

    node.prev = null;
    node.next = null;
  }

  private moveToFront(node: Node<T>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  private evictLRU(): void {
    const lru = this.tail.prev;

    if (lru === null || lru === this.head) {
      return;
    }

    this.removeNode(lru);
    this.map.delete(lru.key);
  }
}

type FlatObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flatten(
  obj: Record<string, unknown>,
  prefix: string,
  seen: WeakSet<object>,
  result: FlatObject
): void {
  if (seen.has(obj)) {
    throw new Error(
      `flattenObject: circular reference detected at prefix "${prefix}"`
    );
  }

  seen.add(obj);

  for (const key of Object.keys(obj)) {
    // Guard against prototype pollution via crafted keys
    if (key === "__proto__" || key === "constructor" || key === "prototype") {
      continue;
    }

    const fullKey = prefix.length > 0 ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (isPlainObject(value) && Object.keys(value).length > 0) {
      // Recurse only into non-empty plain objects; empty objects ({}) are
      // kept as-is because they carry no dot-notation representation
      flatten(value, fullKey, seen, result);
    } else {
      result[fullKey] = value;
    }
  }

  // Remove after processing so the same object can appear at multiple
  // non-circular paths (diamond references) without false positives
  seen.delete(obj);
}

export default function flattenObject(obj: Record<string, unknown>): FlatObject {
  if (!isPlainObject(obj)) {
    throw new TypeError(
      "flattenObject: argument must be a plain object, received " +
        (obj === null ? "null" : typeof obj)
    );
  }

  const result: FlatObject = {};
  flatten(obj, "", new WeakSet(), result);
  return result;
}

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly name: keyof CronExpression;
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute", min: 0, max: 59 },
  { name: "hour", min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month", min: 1, max: 12 },
  { name: "dayOfWeek", min: 0, max: 6 },
];

class CronParseError extends Error {
  constructor(field: string, token: string, reason: string) {
    super(`Invalid cron field "${field}": "${token}" — ${reason}`);
    this.name = "CronParseError";
  }
}

function assertInteger(raw: string, field: string, token: string): number {
  const trimmed = raw.trim();
  if (!/^\d+$/.test(trimmed)) {
    throw new CronParseError(field, token, `"${trimmed}" is not a valid integer`);
  }
  return parseInt(trimmed, 10);
}

function assertInRange(value: number, min: number, max: number, field: string, token: string): number {
  if (value < min || value > max) {
    throw new CronParseError(field, token, `value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
}

function buildRange(start: number, end: number, step: number, min: number, max: number, field: string, token: string): number[] {
  if (start > end) {
    throw new CronParseError(field, token, `range start ${start} exceeds end ${end}`);
  }
  if (step < 1) {
    throw new CronParseError(field, token, `step must be >= 1, got ${step}`);
  }
  const values: number[] = [];
  for (let v = start; v <= end; v += step) {
    values.push(assertInRange(v, min, max, field, token));
  }
  return values;
}

function parseSegment(segment: string, config: FieldConfig): number[] {
  const { name: field, min, max } = config;
  const token = segment.trim();

  if (token === "") {
    throw new CronParseError(field, token, "empty segment");
  }

  // Wildcard with optional step: * or */n
  if (token === "*") {
    return buildRange(min, max, 1, min, max, field, token);
  }

  if (token.startsWith("*/")) {
    const stepRaw = token.slice(2);
    const step = assertInteger(stepRaw, field, token);
    if (step < 1) {
      throw new CronParseError(field, token, `step must be >= 1, got ${step}`);
    }
    return buildRange(min, max, step, min, max, field, token);
  }

  // Range with optional step: n-m or n-m/s
  if (token.includes("-")) {
    const slashIndex = token.indexOf("/");
    const rangePart = slashIndex !== -1 ? token.slice(0, slashIndex) : token;
    const stepPart = slashIndex !== -1 ? token.slice(slashIndex + 1) : "1";

    const dashIndex = rangePart.indexOf("-");
    if (dashIndex <= 0) {
      throw new CronParseError(field, token, "malformed range expression");
    }

    const startRaw = rangePart.slice(0, dashIndex);
    const endRaw = rangePart.slice(dashIndex + 1);

    if (startRaw === "" || endRaw === "") {
      throw new CronParseError(field, token, "range start or end is missing");
    }

    const start = assertInRange(assertInteger(startRaw, field, token), min, max, field, token);
    const end = assertInRange(assertInteger(endRaw, field, token), min, max, field, token);
    const step = assertInteger(stepPart, field, token);

    return buildRange(start, end, step, min, max, field, token);
  }

  // Step on a single value is not standard; treat bare number
  if (token.includes("/")) {
    throw new CronParseError(field, token, `step syntax requires a wildcard or range before "/"`)
  }

  // Single numeric value
  const value = assertInteger(token, field, token);
  return [assertInRange(value, min, max, field, token)];
}

function parseField(raw: string, config: FieldConfig): number[] {
  if (typeof raw !== "string") {
    throw new CronParseError(config.name, String(raw), "field must be a string");
  }

  const segments = raw.split(",");
  if (segments.length === 0) {
    throw new CronParseError(config.name, raw, "field is empty");
  }

  const valueSet = new Set<number>();

  for (const segment of segments) {
    const values = parseSegment(segment, config);
    for (const v of values) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, got ${typeof expression}`);
  }

  const normalized = expression.trim().replace(/\s+/g, " ");

  if (normalized === "") {
    throw new Error("parseCron received an empty expression");
  }

  const parts = normalized.split(" ");

  if (parts.length !== 5) {
    throw new Error(
      `parseCron expects exactly 5 fields (minute hour dayOfMonth month dayOfWeek), got ${parts.length}`
    );
  }

  const [minuteRaw, hourRaw, dayOfMonthRaw, monthRaw, dayOfWeekRaw] = parts;

  return {
    minute: parseField(minuteRaw, FIELD_CONFIGS[0]),
    hour: parseField(hourRaw, FIELD_CONFIGS[1]),
    dayOfMonth: parseField(dayOfMonthRaw, FIELD_CONFIGS[2]),
    month: parseField(monthRaw, FIELD_CONFIGS[3]),
    dayOfWeek: parseField(dayOfWeekRaw, FIELD_CONFIGS[4]),
  };
}

export default parseCron;

interface CronSchedule {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronSchedule;

const FIELD_RANGES: Record<FieldName, readonly [number, number]> = {
  minute:     [0,  59],
  hour:       [0,  23],
  dayOfMonth: [1,  31],
  month:      [1,  12],
  dayOfWeek:  [0,   6],
};

const INTEGER_RE = /^\d+$/;
const RANGE_RE   = /^(\d+)-(\d+)$/;
const STEP_RE    = /^(.+?)\/(\d+)$/;

function assertInBounds(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of bounds [${min}, ${max}] in segment "${context}"`
    );
  }
}

function parseInteger(raw: string, context: string): number {
  if (!INTEGER_RE.test(raw)) {
    throw new SyntaxError(`Expected an integer but got "${raw}" in segment "${context}"`);
  }
  return parseInt(raw, 10);
}

function expandRange(start: number, end: number, step: number, context: string): number[] {
  if (step <= 0) {
    throw new RangeError(`Step must be > 0 but got ${step} in segment "${context}"`);
  }
  if (start > end) {
    throw new RangeError(
      `Range start ${start} exceeds end ${end} in segment "${context}"`
    );
  }
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function parseSegment(segment: string, min: number, max: number): number[] {
  const s = segment.trim();
  if (s === "") {
    throw new SyntaxError(`Empty segment encountered (check for stray commas)`);
  }

  // Step value: */n, a-b/n, or a/n (a/n means a..max step n)
  const stepMatch = STEP_RE.exec(s);
  if (stepMatch !== null) {
    const [, base, stepRaw] = stepMatch;
    const step = parseInteger(stepRaw, s);
    if (step === 0) {
      throw new RangeError(`Step value of 0 is invalid in segment "${s}"`);
    }

    if (base === "*") {
      return expandRange(min, max, step, s);
    }

    const rangeMatch = RANGE_RE.exec(base);
    if (rangeMatch !== null) {
      const start = parseInteger(rangeMatch[1], s);
      const end   = parseInteger(rangeMatch[2], s);
      assertInBounds(start, min, max, s);
      assertInBounds(end,   min, max, s);
      return expandRange(start, end, step, s);
    }

    // Single-start/step: treat as start..max/step
    const start = parseInteger(base, s);
    assertInBounds(start, min, max, s);
    return expandRange(start, max, step, s);
  }

  // Wildcard
  if (s === "*") {
    return expandRange(min, max, 1, s);
  }

  // Range: a-b
  const rangeMatch = RANGE_RE.exec(s);
  if (rangeMatch !== null) {
    const start = parseInteger(rangeMatch[1], s);
    const end   = parseInteger(rangeMatch[2], s);
    assertInBounds(start, min, max, s);
    assertInBounds(end,   min, max, s);
    return expandRange(start, end, 1, s);
  }

  // Single integer
  const value = parseInteger(s, s);
  assertInBounds(value, min, max, s);
  return [value];
}

function parseField(expression: string, min: number, max: number): number[] {
  if (expression === "") {
    throw new SyntaxError(`Field expression cannot be an empty string`);
  }

  const parts = expression.split(",");
  const seen  = new Set<number>();

  for (const part of parts) {
    for (const v of parseSegment(part, min, max)) {
      seen.add(v);
    }
  }

  if (seen.size === 0) {
    throw new Error(`Field "${expression}" produced no valid values — check your ranges`);
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronSchedule {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, received ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError(`Cron expression must not be empty`);
  }

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek), ` +
      `got ${fields.length}: "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  return {
    minute:     parseField(minuteExpr, ...FIELD_RANGES.minute),
    hour:       parseField(hourExpr,   ...FIELD_RANGES.hour),
    dayOfMonth: parseField(domExpr,    ...FIELD_RANGES.dayOfMonth),
    month:      parseField(monthExpr,  ...FIELD_RANGES.month),
    dayOfWeek:  parseField(dowExpr,    ...FIELD_RANGES.dayOfWeek),
  };
}

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly field: keyof CronExpression;
  readonly min: number;
  readonly max: number;
  readonly allowedMax: number; // e.g., dayOfWeek allows 7 as alias for 0
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { field: "minute",     min: 0, max: 59, allowedMax: 59 },
  { field: "hour",       min: 0, max: 23, allowedMax: 23 },
  { field: "dayOfMonth", min: 1, max: 31, allowedMax: 31 },
  { field: "month",      min: 1, max: 12, allowedMax: 12 },
  { field: "dayOfWeek",  min: 0, max: 6,  allowedMax: 7  },
] as const;

function parseIntStrict(raw: string, field: string): number {
  const s = raw.trim();
  if (!/^\d+$/.test(s)) {
    throw new Error(`Expected non-negative integer in field "${field}", got "${raw}"`);
  }
  return parseInt(s, 10);
}

function checkBounds(value: number, config: FieldConfig): void {
  if (value < config.min || value > config.allowedMax) {
    throw new Error(
      `Value ${value} out of valid range [${config.min}–${config.allowedMax}] for field "${config.field}"`
    );
  }
}

function parseToken(token: string, config: FieldConfig): number[] {
  const t = token.trim();

  if (t === "") {
    throw new Error(`Empty token in field "${config.field}"`);
  }

  // Step value: "base/step" — base is *, a range, or a single number
  if (t.includes("/")) {
    const slashIndex = t.indexOf("/");
    const rest = t.slice(slashIndex + 1);

    if (rest.includes("/")) {
      throw new Error(`Multiple "/" separators in field "${config.field}": "${t}"`);
    }

    const base = t.slice(0, slashIndex);
    const step = parseIntStrict(rest, config.field);

    if (step <= 0) {
      throw new Error(
        `Step must be a positive integer in field "${config.field}", got ${step}`
      );
    }

    let rangeMin: number;
    let rangeMax: number;

    if (base === "*") {
      rangeMin = config.min;
      rangeMax = config.max;
    } else if (base.includes("-")) {
      const dashParts = base.split("-");
      if (dashParts.length !== 2) {
        throw new Error(`Invalid range "${base}" in step for field "${config.field}"`);
      }
      rangeMin = parseIntStrict(dashParts[0], config.field);
      rangeMax = parseIntStrict(dashParts[1], config.field);
      checkBounds(rangeMin, config);
      checkBounds(rangeMax, config);
      if (rangeMin > rangeMax) {
        throw new Error(
          `Range start ${rangeMin} > end ${rangeMax} in field "${config.field}"`
        );
      }
    } else {
      rangeMin = parseIntStrict(base, config.field);
      checkBounds(rangeMin, config);
      // Normalize dayOfWeek 7 (Sunday alias) before expanding so the loop doesn't
      // immediately overshoot config.max (6)
      if (config.field === "dayOfWeek" && rangeMin === 7) {
        rangeMin = 0;
      }
      rangeMax = config.max;
    }

    const result: number[] = [];
    for (let v = rangeMin; v <= rangeMax; v += step) {
      result.push(v);
    }
    return result;
  }

  // Wildcard: expands to every value in [min, max]
  if (t === "*") {
    const result: number[] = [];
    for (let v = config.min; v <= config.max; v++) {
      result.push(v);
    }
    return result;
  }

  // Range: "start-end"
  if (t.includes("-")) {
    const dashParts = t.split("-");
    if (dashParts.length !== 2) {
      throw new Error(`Invalid range "${t}" in field "${config.field}"`);
    }
    const start = parseIntStrict(dashParts[0], config.field);
    const end   = parseIntStrict(dashParts[1], config.field);
    checkBounds(start, config);
    checkBounds(end, config);
    if (start > end) {
      throw new Error(
        `Range start ${start} > end ${end} in field "${config.field}"`
      );
    }
    const result: number[] = [];
    for (let v = start; v <= end; v++) {
      result.push(v);
    }
    return result;
  }

  // Single number
  const value = parseIntStrict(t, config.field);
  checkBounds(value, config);
  return [value];
}

function parseField(fieldStr: string, config: FieldConfig): number[] {
  if (typeof fieldStr !== "string") {
    throw new TypeError(`Field "${config.field}" must be a string`);
  }

  const trimmed = fieldStr.trim();
  if (trimmed === "") {
    throw new Error(`Field "${config.field}" cannot be empty`);
  }

  const tokens = trimmed.split(",");
  if (tokens.length === 0) {
    throw new Error(`Field "${config.field}" produced no tokens`);
  }

  const seen = new Set<number>();

  for (const token of tokens) {
    const values = parseToken(token, config);
    for (const v of values) {
      seen.add(v);
    }
  }

  // Normalize dayOfWeek: 7 is an alias for Sunday (0)
  if (config.field === "dayOfWeek" && seen.has(7)) {
    seen.delete(7);
    seen.add(0);
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, received ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new Error("Cron expression cannot be empty");
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteStr, hourStr, dayOfMonthStr, monthStr, dayOfWeekStr] = fields;

  return {
    minute:     parseField(minuteStr,     FIELD_CONFIGS[0]),
    hour:       parseField(hourStr,       FIELD_CONFIGS[1]),
    dayOfMonth: parseField(dayOfMonthStr, FIELD_CONFIGS[2]),
    month:      parseField(monthStr,      FIELD_CONFIGS[3]),
    dayOfWeek:  parseField(dayOfWeekStr,  FIELD_CONFIGS[4]),
  };
}

type Primitive = string | number | boolean | null | undefined | bigint | symbol;

type NestedObject = {
  [key: string]: Primitive | NestedObject | Array<unknown>;
};

type FlattenedObject = Record<string, Primitive | Array<unknown>>;

function flattenObject(
  input: unknown,
  prefix: string = "",
  result: FlattenedObject = {}
): FlattenedObject {
  if (input === null || input === undefined) {
    if (prefix !== "") {
      result[prefix] = input as Primitive;
    }
    return result;
  }

  if (typeof input !== "object" || Array.isArray(input)) {
    if (prefix !== "") {
      result[prefix] = input as Primitive | Array<unknown>;
    }
    return result;
  }

  const obj = input as Record<string, unknown>;
  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix !== "") {
      result[prefix] = {} as unknown as Primitive;
    }
    return result;
  }

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) {
      continue;
    }

    const sanitizedKey = String(key);
    const newPrefix = prefix !== "" ? `${prefix}.${sanitizedKey}` : sanitizedKey;
    const value = obj[key];

    if (
      value !== null &&
      value !== undefined &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value, newPrefix, result);
    } else {
      result[newPrefix] = value as Primitive | Array<unknown>;
    }
  }

  return result;
}

export default flattenObject;

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const FIELD_NAMES = Object.keys(FIELD_RANGES) as (keyof CronFields)[];

function clamp(value: number, min: number, max: number): number {
  return Math.max(min, Math.min(max, value));
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(
      `Invalid value ${value} in "${context}": must be an integer between ${min} and ${max}`
    );
  }
}

function parseInteger(raw: string, context: string): number {
  const trimmed = raw.trim();
  if (!/^\d+$/.test(trimmed)) {
    throw new SyntaxError(`Expected an integer in "${context}", got "${trimmed}"`);
  }
  return parseInt(trimmed, 10);
}

function expandWildcard(min: number, max: number): number[] {
  return Array.from({ length: max - min + 1 }, (_, i) => min + i);
}

function parseSegment(segment: string, min: number, max: number): number[] {
  const trimmed = segment.trim();

  if (trimmed === "") {
    throw new SyntaxError(`Empty cron segment`);
  }

  // Step value: */N or start-end/N
  if (trimmed.includes("/")) {
    const slashIndex = trimmed.indexOf("/");
    const left  = trimmed.slice(0, slashIndex).trim();
    const right = trimmed.slice(slashIndex + 1).trim();

    const step = parseInteger(right, trimmed);
    if (step < 1) {
      throw new RangeError(`Step value must be >= 1 in "${trimmed}"`);
    }

    let rangeMin = min;
    let rangeMax = max;

    if (left !== "*") {
      // Explicit range before the slash, e.g. "0-30/5"
      if (left.includes("-")) {
        const dashIndex = left.indexOf("-");
        rangeMin = parseInteger(left.slice(0, dashIndex), trimmed);
        rangeMax = parseInteger(left.slice(dashIndex + 1), trimmed);
        assertInRange(rangeMin, min, max, trimmed);
        assertInRange(rangeMax, min, max, trimmed);
        if (rangeMin > rangeMax) {
          throw new RangeError(`Range start > end in "${trimmed}"`);
        }
      } else {
        // Single number before slash, e.g. "5/15" means start at 5, step 15
        rangeMin = parseInteger(left, trimmed);
        assertInRange(rangeMin, min, max, trimmed);
        rangeMax = max;
      }
    }

    const values: number[] = [];
    for (let v = rangeMin; v <= rangeMax; v += step) {
      values.push(v);
    }
    return values;
  }

  // Wildcard
  if (trimmed === "*") {
    return expandWildcard(min, max);
  }

  // Range: N-M
  if (trimmed.includes("-")) {
    const dashIndex = trimmed.indexOf("-");
    const start = parseInteger(trimmed.slice(0, dashIndex), trimmed);
    const end   = parseInteger(trimmed.slice(dashIndex + 1), trimmed);
    assertInRange(start, min, max, trimmed);
    assertInRange(end,   min, max, trimmed);
    if (start > end) {
      throw new RangeError(`Range start > end in "${trimmed}"`);
    }
    return Array.from({ length: end - start + 1 }, (_, i) => start + i);
  }

  // Single number
  const value = parseInteger(trimmed, trimmed);
  assertInRange(value, min, max, trimmed);
  return [value];
}

function parseField(
  field: string,
  fieldName: keyof CronFields
): number[] {
  if (typeof field !== "string") {
    throw new TypeError(`Expected a string for field "${fieldName}"`);
  }

  const { min, max } = FIELD_RANGES[fieldName];
  const parts = field.split(",");

  if (parts.length === 0) {
    throw new SyntaxError(`Empty field "${fieldName}"`);
  }

  const valueSet = new Set<number>();
  for (const part of parts) {
    const expanded = parseSegment(part, min, max);
    for (const v of expanded) {
      valueSet.add(clamp(v, min, max));
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${trimmed}"`
    );
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_NAMES.length; i++) {
    const name = FIELD_NAMES[i];
    result[name] = parseField(fields[i], name);
  }

  return result;
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronFields;

const FIELD_RANGES: Record<FieldName, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
};

const FIELD_NAMES: ReadonlyArray<FieldName> = [
  "minute", "hour", "dayOfMonth", "month", "dayOfWeek",
];

function isNonNegativeInteger(s: string): boolean {
  return /^\d+$/.test(s);
}

function parseInteger(s: string, context: string): number {
  if (!isNonNegativeInteger(s)) {
    throw new Error(`Expected a non-negative integer, got "${s}" in "${context}"`);
  }
  return parseInt(s, 10);
}

function expandRange(rangeStart: number, rangeEnd: number, step: number, fieldMin: number, fieldMax: number, expr: string): number[] {
  if (rangeStart < fieldMin || rangeStart > fieldMax) {
    throw new Error(`Value ${rangeStart} out of bounds [${fieldMin}-${fieldMax}] in "${expr}"`);
  }
  if (rangeEnd < fieldMin || rangeEnd > fieldMax) {
    throw new Error(`Value ${rangeEnd} out of bounds [${fieldMin}-${fieldMax}] in "${expr}"`);
  }
  if (rangeStart > rangeEnd) {
    throw new Error(`Range start ${rangeStart} must not exceed end ${rangeEnd} in "${expr}"`);
  }
  if (step <= 0) {
    throw new Error(`Step must be a positive integer, got ${step} in "${expr}"`);
  }

  const result: number[] = [];
  for (let i = rangeStart; i <= rangeEnd; i += step) {
    result.push(i);
  }
  return result;
}

function parseSegment(segment: string, fieldMin: number, fieldMax: number): number[] {
  // Handle step: base/step — base may be "*", "n", or "n-m"
  if (segment.includes("/")) {
    const slashCount = (segment.match(/\//g) ?? []).length;
    if (slashCount !== 1) {
      throw new Error(`Invalid step expression "${segment}": multiple "/" characters`);
    }

    const slashIdx = segment.indexOf("/");
    const baseExpr = segment.slice(0, slashIdx);
    const stepStr  = segment.slice(slashIdx + 1);

    if (baseExpr === "") {
      throw new Error(`Missing base in step expression "${segment}"`);
    }
    if (stepStr === "") {
      throw new Error(`Missing step value in "${segment}"`);
    }

    const step = parseInteger(stepStr, segment);

    if (baseExpr === "*") {
      return expandRange(fieldMin, fieldMax, step, fieldMin, fieldMax, segment);
    }

    if (baseExpr.includes("-")) {
      const [startStr, endStr, ...extra] = baseExpr.split("-");
      if (extra.length > 0) {
        throw new Error(`Invalid range "${baseExpr}" in "${segment}"`);
      }
      const start = parseInteger(startStr, segment);
      const end   = parseInteger(endStr,   segment);
      return expandRange(start, end, step, fieldMin, fieldMax, segment);
    }

    // Single-number base: e.g. "5/15" means start=5 to fieldMax, step 15
    const start = parseInteger(baseExpr, segment);
    return expandRange(start, fieldMax, step, fieldMin, fieldMax, segment);
  }

  // Handle plain range: n-m
  if (segment.includes("-")) {
    const parts = segment.split("-");
    if (parts.length !== 2) {
      throw new Error(`Invalid range expression "${segment}": expected exactly one "-"`);
    }
    const [startStr, endStr] = parts;
    const start = parseInteger(startStr, segment);
    const end   = parseInteger(endStr,   segment);
    return expandRange(start, end, 1, fieldMin, fieldMax, segment);
  }

  // Handle wildcard
  if (segment === "*") {
    return expandRange(fieldMin, fieldMax, 1, fieldMin, fieldMax, segment);
  }

  // Handle single integer
  const value = parseInteger(segment, segment);
  if (value < fieldMin || value > fieldMax) {
    throw new Error(`Value ${value} out of bounds [${fieldMin}-${fieldMax}]`);
  }
  return [value];
}

function parseField(expr: string, fieldMin: number, fieldMax: number): number[] {
  if (expr === "") {
    throw new Error("Field expression must not be empty");
  }

  // Handle comma-separated list — must split before anything else
  const segments = expr.split(",");

  if (segments.some((s) => s === "")) {
    throw new Error(`Empty element in list "${expr}": trailing/double commas are not allowed`);
  }

  const values = segments.flatMap((seg) => parseSegment(seg, fieldMin, fieldMax));

  // Deduplicate and sort ascending — order must be deterministic
  return [...new Set(values)].sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, received ${typeof expression}`);
  }

  const trimmed = expression.trim();

  if (trimmed === "") {
    throw new Error("Cron expression must not be empty");
  }

  const rawFields = trimmed.split(/\s+/);

  if (rawFields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 whitespace-separated fields, got ${rawFields.length}: "${expression}"`,
    );
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_NAMES.length; i++) {
    const name = FIELD_NAMES[i];
    const { min, max } = FIELD_RANGES[name];

    try {
      result[name] = parseField(rawFields[i], min, max);
    } catch (err) {
      throw new Error(
        `Invalid "${name}" field (position ${i + 1}) "${rawFields[i]}": ${err instanceof Error ? err.message : String(err)}`,
      );
    }
  }

  return result;
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly name: string;
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute", min: 0, max: 59 },
  { name: "hour", min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month", min: 1, max: 12 },
  { name: "dayOfWeek", min: 0, max: 6 },
] as const;

function assertInRange(
  value: number,
  min: number,
  max: number,
  fieldName: string
): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of valid range [${min}, ${max}] for field "${fieldName}"`
    );
  }
}

function assertStepValid(step: number, fieldName: string): void {
  if (!Number.isInteger(step) || step < 1) {
    throw new RangeError(
      `Step value ${step} must be a positive integer in field "${fieldName}"`
    );
  }
}

function expandRange(start: number, end: number, step: number): number[] {
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseAtom(token: string, config: FieldConfig): number[] {
  const { name, min, max } = config;

  if (token === "*") {
    return expandRange(min, max, 1);
  }

  const stepWildcardMatch = /^\*\/(\d+)$/.exec(token);
  if (stepWildcardMatch !== null) {
    const step = parseInt(stepWildcardMatch[1]!, 10);
    assertStepValid(step, name);
    return expandRange(min, max, step);
  }

  const rangeStepMatch = /^(\d+)-(\d+)\/(\d+)$/.exec(token);
  if (rangeStepMatch !== null) {
    const start = parseInt(rangeStepMatch[1]!, 10);
    const end = parseInt(rangeStepMatch[2]!, 10);
    const step = parseInt(rangeStepMatch[3]!, 10);
    assertInRange(start, min, max, name);
    assertInRange(end, min, max, name);
    if (start > end) {
      throw new RangeError(
        `Range start ${start} exceeds end ${end} in field "${name}"`
      );
    }
    assertStepValid(step, name);
    return expandRange(start, end, step);
  }

  const rangeMatch = /^(\d+)-(\d+)$/.exec(token);
  if (rangeMatch !== null) {
    const start = parseInt(rangeMatch[1]!, 10);
    const end = parseInt(rangeMatch[2]!, 10);
    assertInRange(start, min, max, name);
    assertInRange(end, min, max, name);
    if (start > end) {
      throw new RangeError(
        `Range start ${start} exceeds end ${end} in field "${name}"`
      );
    }
    return expandRange(start, end, 1);
  }

  const singleMatch = /^(\d+)$/.exec(token);
  if (singleMatch !== null) {
    const value = parseInt(singleMatch[1]!, 10);
    assertInRange(value, min, max, name);
    return [value];
  }

  throw new SyntaxError(
    `Unrecognized token "${token}" in field "${name}"`
  );
}

function parseField(expression: string, config: FieldConfig): number[] {
  const trimmed = expression.trim();

  if (trimmed === "") {
    throw new SyntaxError(`Field "${config.name}" must not be empty`);
  }

  if (!trimmed.includes(",")) {
    return parseAtom(trimmed, config);
  }

  const parts = trimmed.split(",");
  const seen = new Set<number>();

  for (const part of parts) {
    const trimmedPart = part.trim();

    if (trimmedPart === "") {
      throw new SyntaxError(
        `Empty segment in comma-separated list for field "${config.name}"`
      );
    }

    if (trimmedPart === "*" || /^\*\/\d+$/.test(trimmedPart)) {
      throw new SyntaxError(
        `Wildcard "${trimmedPart}" is not valid inside a comma-separated list in field "${config.name}"`
      );
    }

    for (const value of parseAtom(trimmedPart, config)) {
      seen.add(value);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(
      `Cron expression must be a string, got ${typeof expression}`
    );
  }

  const trimmed = expression.trim();

  if (trimmed === "") {
    throw new SyntaxError("Cron expression must not be empty");
  }

  const parts = trimmed.split(/\s+/);

  if (parts.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${parts.length}: "${expression}"`
    );
  }

  const [
    minuteExpr,
    hourExpr,
    dayOfMonthExpr,
    monthExpr,
    dayOfWeekExpr,
  ] = parts as [string, string, string, string, string];

  return {
    minute: parseField(minuteExpr, FIELD_CONFIGS[0]!),
    hour: parseField(hourExpr, FIELD_CONFIGS[1]!),
    dayOfMonth: parseField(dayOfMonthExpr, FIELD_CONFIGS[2]!),
    month: parseField(monthExpr, FIELD_CONFIGS[3]!),
    dayOfWeek: parseField(dayOfWeekExpr, FIELD_CONFIGS[4]!),
  };
}

type Scalar = string | number | boolean | null | undefined | bigint | symbol | Function | Date | RegExp;

type NestedObject = {
  [key: string]: Scalar | NestedObject | unknown[] | Record<string, unknown>;
};

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function recurse(
  obj: Record<string, unknown>,
  prefix: string,
  result: Record<string, unknown>,
  ancestors: WeakSet<object>
): void {
  if (ancestors.has(obj)) {
    throw new TypeError(
      `Circular reference detected at key "${prefix || "(root)"}"`
    );
  }

  ancestors.add(obj);

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    // Empty plain object — preserve as leaf so callers know the key existed
    if (prefix !== "") {
      result[prefix] = {};
    }
  } else {
    for (const key of keys) {
      if (key === "") {
        // Empty-string keys would produce ambiguous dot-notation paths
        throw new TypeError(
          `Empty-string key found under "${prefix || "(root)"}" — cannot produce unambiguous dot-notation`
        );
      }

      const fullKey = prefix !== "" ? `${prefix}.${key}` : key;
      const value = obj[key];

      if (isPlainObject(value)) {
        recurse(value as Record<string, unknown>, fullKey, result, ancestors);
      } else {
        result[fullKey] = value;
      }
    }
  }

  ancestors.delete(obj); // Remove on exit so sibling branches may share the same reference
}

export default function flattenObject(
  input: NestedObject
): Record<string, unknown> {
  if (!isPlainObject(input)) {
    throw new TypeError(
      `flattenObject expects a plain object, received ${
        input === null ? "null" : typeof input
      }`
    );
  }

  const result: Record<string, unknown> = {};
  recurse(input as Record<string, unknown>, "", result, new WeakSet());
  return result;
}

interface Node<T> {
  key: string;
  value: T;
  prev: Node<T> | null;
  next: Node<T> | null;
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;
  private readonly head: Node<T>;
  private readonly tail: Node<T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 1) {
      throw new RangeError(`Capacity must be a positive integer, got: ${capacity}`);
    }

    this.capacity = capacity;
    this.map = new Map();

    this.head = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.tail = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key: string): T | undefined {
    if (typeof key !== "string") return undefined;

    const node = this.map.get(key);
    if (node === undefined) return undefined;

    this.moveToFront(node);
    return node.value;
  }

  set(key: string, value: T): void {
    if (typeof key !== "string") {
      throw new TypeError(`Key must be a string, got: ${typeof key}`);
    }

    const existing = this.map.get(key);

    if (existing !== undefined) {
      existing.value = value;
      this.moveToFront(existing);
      return;
    }

    const node: Node<T> = { key, value, prev: null, next: null };
    this.map.set(key, node);
    this.insertAtFront(node);

    if (this.map.size > this.capacity) {
      this.evictLRU();
    }
  }

  get size(): number {
    return this.map.size;
  }

  has(key: string): boolean {
    return typeof key === "string" && this.map.has(key);
  }

  delete(key: string): boolean {
    if (typeof key !== "string") return false;

    const node = this.map.get(key);
    if (node === undefined) return false;

    this.removeNode(node);
    this.map.delete(key);
    return true;
  }

  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  keys(): string[] {
    const result: string[] = [];
    let current = this.head.next;
    while (current !== null && current !== this.tail) {
      result.push(current.key);
      current = current.next;
    }
    return result;
  }

  private insertAtFront(node: Node<T>): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  private removeNode(node: Node<T>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    node.prev = null;
    node.next = null;
  }

  private moveToFront(node: Node<T>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  private evictLRU(): void {
    const lru = this.tail.prev;
    if (lru === null || lru === this.head) return;

    this.removeNode(lru);
    this.map.delete(lru.key);
  }
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly cache: Map<string, T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity)) {
      throw new TypeError(`Capacity must be an integer, got: ${capacity}`);
    }
    if (capacity < 0) {
      throw new RangeError(`Capacity must be non-negative, got: ${capacity}`);
    }
    this.capacity = capacity;
    this.cache = new Map<string, T>();
  }

  get(key: string): T | undefined {
    if (!this.cache.has(key)) {
      return undefined;
    }
    // Promote to most-recently-used by re-inserting at tail
    const value = this.cache.get(key) as T;
    this.cache.delete(key);
    this.cache.set(key, value);
    return value;
  }

  set(key: string, value: T): void {
    if (this.capacity === 0) {
      return;
    }

    if (this.cache.has(key)) {
      // Remove before re-inserting so it moves to tail (most-recently-used)
      this.cache.delete(key);
    } else if (this.cache.size >= this.capacity) {
      // Map iterator yields entries in insertion order; first = least-recently-used
      const lruKey = this.cache.keys().next().value;
      if (lruKey !== undefined) {
        this.cache.delete(lruKey);
      }
    }

    this.cache.set(key, value);
  }

  get size(): number {
    return this.cache.size;
  }

  has(key: string): boolean {
    return this.cache.has(key);
  }

  delete(key: string): boolean {
    return this.cache.delete(key);
  }

  clear(): void {
    this.cache.clear();
  }
}

interface Node<T> {
  key: string;
  value: T;
  prev: Node<T> | null;
  next: Node<T> | null;
}

class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;
  // Sentinel head (oldest) and tail (newest) — avoids null-check branches everywhere
  private readonly head: Node<T>;
  private readonly tail: Node<T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity)) {
      throw new TypeError(`LRUCache capacity must be an integer, got: ${capacity}`);
    }
    // Clamp to 0 so the cache is safely inert rather than silently broken
    this.capacity = Math.max(0, capacity);
    this.map = new Map();

    // Sentinels carry no real data; cast to satisfy the type without polluting the API
    this.head = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.tail = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key: string): T | undefined {
    const node = this.map.get(key);
    if (node === undefined) {
      return undefined;
    }
    // Promote to most-recently-used position (just before tail)
    this.detach(node);
    this.insertBeforeTail(node);
    return node.value;
  }

  set(key: string, value: T): void {
    // Zero-capacity cache: accept the call but store nothing
    if (this.capacity === 0) {
      return;
    }

    const existing = this.map.get(key);
    if (existing !== undefined) {
      // Update in place and promote — no eviction needed
      existing.value = value;
      this.detach(existing);
      this.insertBeforeTail(existing);
      return;
    }

    // Evict least-recently-used (the node just after the head sentinel) before inserting
    if (this.map.size >= this.capacity) {
      const lru = this.head.next!;
      this.detach(lru);
      this.map.delete(lru.key);
    }

    const node: Node<T> = { key, value, prev: null, next: null };
    this.insertBeforeTail(node);
    this.map.set(key, node);
  }

  // ── private helpers ────────────────────────────────────────────────────────

  private detach(node: Node<T>): void {
    // Every real node always has non-null prev/next because sentinels bookend the list
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    node.prev = null;
    node.next = null;
  }

  private insertBeforeTail(node: Node<T>): void {
    const prev = this.tail.prev!;
    prev.next = node;
    node.prev = prev;
    node.next = this.tail;
    this.tail.prev = node;
  }
}

export default LRUCache;

type Primitive = string | number | boolean | null | undefined | bigint | symbol;

type FlattenedObject = Record<string, Primitive>;

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  input: unknown,
  maxDepth: number = 100
): FlattenedObject {
  if (input === null || input === undefined) {
    return {};
  }

  if (!isPlainObject(input)) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${Array.isArray(input) ? "array" : typeof input}`
    );
  }

  const result: FlattenedObject = {};

  function recurse(current: Record<string, unknown>, prefix: string, depth: number): void {
    if (depth > maxDepth) {
      throw new RangeError(
        `flattenObject exceeded maximum depth of ${maxDepth}. Possible circular reference or deeply nested structure.`
      );
    }

    const keys = Object.keys(current);

    if (keys.length === 0 && prefix !== "") {
      // Preserve empty objects as a value (empty string sentinel not ideal;
      // we skip empty objects to avoid ambiguity with leaf values).
      return;
    }

    for (const key of keys) {
      if (key === "") {
        // Skip empty string keys to avoid producing leading/trailing/double dots.
        continue;
      }

      const fullKey = prefix === "" ? key : `${prefix}.${key}`;
      const value = current[key];

      if (isPlainObject(value)) {
        const nested = value as Record<string, unknown>;
        if (Object.keys(nested).length === 0) {
          // Empty nested object — represent as undefined leaf so the key is preserved.
          result[fullKey] = undefined;
        } else {
          recurse(nested, fullKey, depth + 1);
        }
      } else if (!Array.isArray(value) && typeof value === "object" && value !== null) {
        // Non-plain objects (Date, Map, Set, etc.) — store as-is under the key.
        result[fullKey] = value as unknown as Primitive;
      } else {
        result[fullKey] = value as Primitive;
      }
    }
  }

  recurse(input, "", 0);
  return result;
}

export default flattenObject;

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly name: keyof CronFields;
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute",     min: 0, max: 59 },
  { name: "hour",       min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month",      min: 1, max: 12 },
  { name: "dayOfWeek",  min: 0, max: 6  },
] as const;

function expandRange(start: number, end: number, step: number, min: number, max: number, fieldName: string): number[] {
  if (!Number.isInteger(start) || !Number.isInteger(end) || !Number.isInteger(step)) {
    throw new TypeError(`Non-integer value in range for field "${fieldName}"`);
  }
  if (step <= 0) {
    throw new RangeError(`Step must be a positive integer, got ${step} in field "${fieldName}"`);
  }
  if (start < min || start > max) {
    throw new RangeError(`Range start ${start} is out of bounds [${min}-${max}] for field "${fieldName}"`);
  }
  if (end < min || end > max) {
    throw new RangeError(`Range end ${end} is out of bounds [${min}-${max}] for field "${fieldName}"`);
  }
  if (start > end) {
    throw new RangeError(`Range start ${start} must not exceed end ${end} in field "${fieldName}"`);
  }

  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseInteger(raw: string, fieldName: string): number {
  const trimmed = raw.trim();
  if (!/^-?\d+$/.test(trimmed)) {
    throw new TypeError(`Expected an integer, got "${raw}" in field "${fieldName}"`);
  }
  return parseInt(trimmed, 10);
}

function parseSegment(segment: string, min: number, max: number, fieldName: string): number[] {
  const trimmed = segment.trim();

  if (trimmed.length === 0) {
    throw new SyntaxError(`Empty segment in field "${fieldName}"`);
  }

  // Step expression: <range-or-wildcard>/<step>
  if (trimmed.includes("/")) {
    const slashParts = trimmed.split("/");
    if (slashParts.length !== 2) {
      throw new SyntaxError(`Invalid step expression "${trimmed}" in field "${fieldName}": expected exactly one "/"`);
    }
    const [rangePart, stepStr] = slashParts;
    const step = parseInteger(stepStr, fieldName);

    if (rangePart.trim() === "*") {
      return expandRange(min, max, step, min, max, fieldName);
    }

    if (rangePart.includes("-")) {
      const dashParts = rangePart.split("-");
      if (dashParts.length !== 2) {
        throw new SyntaxError(`Invalid range "${rangePart}" in step expression for field "${fieldName}"`);
      }
      const start = parseInteger(dashParts[0], fieldName);
      const end   = parseInteger(dashParts[1], fieldName);
      return expandRange(start, end, step, min, max, fieldName);
    }

    // Single-start step: start/step  → [start, start+step, ...] up to max
    const start = parseInteger(rangePart, fieldName);
    return expandRange(start, max, step, min, max, fieldName);
  }

  // Wildcard
  if (trimmed === "*") {
    return expandRange(min, max, 1, min, max, fieldName);
  }

  // Range: start-end
  if (trimmed.includes("-")) {
    const dashParts = trimmed.split("-");
    if (dashParts.length !== 2) {
      throw new SyntaxError(`Invalid range expression "${trimmed}" in field "${fieldName}": expected exactly one "-"`);
    }
    const start = parseInteger(dashParts[0], fieldName);
    const end   = parseInteger(dashParts[1], fieldName);
    return expandRange(start, end, 1, min, max, fieldName);
  }

  // Single numeric value
  const value = parseInteger(trimmed, fieldName);
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of bounds [${min}-${max}] for field "${fieldName}"`);
  }
  return [value];
}

function parseField(raw: string, config: FieldConfig): number[] {
  const trimmed = raw.trim();

  if (trimmed.length === 0) {
    throw new SyntaxError(`Field "${config.name}" must not be empty`);
  }

  const valueSet = new Set<number>();

  // Comma-separated list: each item is a segment
  const items = trimmed.split(",");
  for (const item of items) {
    const cleaned = item.trim();
    if (cleaned.length === 0) {
      throw new SyntaxError(`Empty item in comma-separated list for field "${config.name}"`);
    }
    const values = parseSegment(cleaned, config.min, config.max, config.name);
    for (const v of values) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export function parseCron(expression: unknown): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(`Cron expression must be a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed.length === 0) {
    throw new SyntaxError("Cron expression must not be empty or whitespace");
  }

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 whitespace-separated fields, got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as CronFields;
  for (let i = 0; i < FIELD_CONFIGS.length; i++) {
    const config = FIELD_CONFIGS[i];
    result[config.name] = parseField(fields[i], config);
  }

  return result;
}

export default parseCron;

class Node<T> {
  key: string;
  value: T;
  prev: Node<T> | null = null;
  next: Node<T> | null = null;

  constructor(key: string, value: T) {
    this.key = key;
    this.value = value;
  }
}

export class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;
  // Sentinel head (most recent) and tail (least recent)
  private readonly head: Node<T>;
  private readonly tail: Node<T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 0) {
      throw new RangeError(
        `LRUCache capacity must be a non-negative integer, got: ${capacity}`
      );
    }
    this.capacity = capacity;
    this.map = new Map();
    // Sentinels hold no real data; their key/value are never exposed
    this.head = new Node<T>("__HEAD__", undefined as unknown as T);
    this.tail = new Node<T>("__TAIL__", undefined as unknown as T);
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key: string): T | undefined {
    const node = this.map.get(key);
    if (node === undefined) {
      return undefined;
    }
    // Promote to most-recently-used position
    this.detach(node);
    this.attachAfterHead(node);
    return node.value;
  }

  set(key: string, value: T): void {
    // Zero-capacity cache: accept calls silently, store nothing
    if (this.capacity === 0) {
      return;
    }

    const existing = this.map.get(key);
    if (existing !== undefined) {
      // Update in place and promote — no eviction needed
      existing.value = value;
      this.detach(existing);
      this.attachAfterHead(existing);
      return;
    }

    // Evict LRU before inserting when at capacity
    if (this.map.size >= this.capacity) {
      const lru = this.tail.prev;
      if (lru === null || lru === this.head) {
        // Sentinel integrity violation — should never happen
        throw new Error("LRUCache internal state is corrupt: sentinel breach");
      }
      this.detach(lru);
      this.map.delete(lru.key);
    }

    const node = new Node<T>(key, value);
    this.attachAfterHead(node);
    this.map.set(key, node);
  }

  get size(): number {
    return this.map.size;
  }

  // ── Private helpers ────────────────────────────────────────────────────────

  /** Remove a node from its current position in the list. */
  private detach(node: Node<T>): void {
    const { prev, next } = node;
    if (prev === null || next === null) {
      throw new Error(
        `LRUCache internal state is corrupt: node "${node.key}" has null link`
      );
    }
    prev.next = next;
    next.prev = prev;
    node.prev = null;
    node.next = null;
  }

  /** Insert a detached node immediately after the head sentinel (MRU slot). */
  private attachAfterHead(node: Node<T>): void {
    const second = this.head.next;
    if (second === null) {
      throw new Error(
        "LRUCache internal state is corrupt: head.next is null"
      );
    }
    this.head.next = node;
    node.prev = this.head;
    node.next = second;
    second.prev = node;
  }
}

export default LRUCache;

type Primitive = string | number | boolean | null | undefined | bigint | symbol;
type FlatRecord = Record<string, Primitive>;
type NestedObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  input: unknown,
  prefix = "",
  seen = new WeakSet<object>(),
  result: FlatRecord = {}
): FlatRecord {
  if (input === null || input === undefined || typeof input !== "object") {
    if (prefix !== "") result[prefix] = input as Primitive;
    return result;
  }

  const obj = input as object;

  if (seen.has(obj)) {
    // Circular reference — emit a sentinel rather than infinitely recurse
    if (prefix !== "") result[prefix] = "[Circular]";
    return result;
  }

  seen.add(obj);

  const entries = Array.isArray(obj)
    ? (obj as unknown[]).map((v, i) => [String(i), v] as [string, unknown])
    : Object.entries(obj as NestedObject);

  if (entries.length === 0) {
    // Preserve empty object/array as explicit leaf so callers know it existed
    if (prefix !== "") result[prefix] = Array.isArray(obj) ? ("[]" as unknown as Primitive) : ("{}" as unknown as Primitive);
    seen.delete(obj);
    return result;
  }

  for (const [key, value] of entries) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    const fullKey = prefix === "" ? key : `${prefix}.${key}`;

    if (isPlainObject(value) || Array.isArray(value)) {
      flattenObject(value, fullKey, seen, result);
    } else {
      result[fullKey] = value as Primitive;
    }
  }

  seen.delete(obj);
  return result;
}

export default flattenObject;

interface Node<T> {
  key: string;
  value: T;
  prev: Node<T> | null;
  next: Node<T> | null;
}

class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;
  private head: Node<T> | null; // most recently used
  private tail: Node<T> | null; // least recently used

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 1) {
      throw new RangeError(
        `LRUCache capacity must be a positive integer, got: ${capacity}`
      );
    }
    this.capacity = capacity;
    this.map = new Map();
    this.head = null;
    this.tail = null;
  }

  get(key: string): T | undefined {
    if (typeof key !== "string") return undefined;

    const node = this.map.get(key);
    if (node === undefined) return undefined;

    this.moveToHead(node);
    return node.value;
  }

  set(key: string, value: T): void {
    if (typeof key !== "string") {
      throw new TypeError(`LRUCache key must be a string, got: ${typeof key}`);
    }

    const existing = this.map.get(key);

    if (existing !== undefined) {
      existing.value = value;
      this.moveToHead(existing);
      return;
    }

    const node: Node<T> = { key, value, prev: null, next: null };
    this.map.set(key, node);
    this.prependHead(node);

    if (this.map.size > this.capacity) {
      this.evictTail();
    }
  }

  get size(): number {
    return this.map.size;
  }

  has(key: string): boolean {
    return typeof key === "string" && this.map.has(key);
  }

  delete(key: string): boolean {
    if (typeof key !== "string") return false;

    const node = this.map.get(key);
    if (node === undefined) return false;

    this.removeNode(node);
    this.map.delete(key);
    return true;
  }

  clear(): void {
    this.map.clear();
    this.head = null;
    this.tail = null;
  }

  keys(): string[] {
    const result: string[] = [];
    let current = this.head;
    while (current !== null) {
      result.push(current.key);
      current = current.next;
    }
    return result;
  }

  private prependHead(node: Node<T>): void {
    node.prev = null;
    node.next = this.head;

    if (this.head !== null) {
      this.head.prev = node;
    }

    this.head = node;

    if (this.tail === null) {
      this.tail = node;
    }
  }

  private removeNode(node: Node<T>): void {
    if (node.prev !== null) {
      node.prev.next = node.next;
    } else {
      // node is head
      this.head = node.next;
    }

    if (node.next !== null) {
      node.next.prev = node.prev;
    } else {
      // node is tail
      this.tail = node.prev;
    }

    node.prev = null;
    node.next = null;
  }

  private moveToHead(node: Node<T>): void {
    if (node === this.head) return;
    this.removeNode(node);
    this.prependHead(node);
  }

  private evictTail(): void {
    if (this.tail === null) return;
    const lru = this.tail;
    this.removeNode(lru);
    this.map.delete(lru.key);
  }
}

export default LRUCache;

export interface ParsedCron {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type CronField = keyof ParsedCron;

interface FieldMeta {
  min: number;
  max: number;
}

const FIELD_META: Record<CronField, FieldMeta> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const FIELD_ORDER: CronField[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

const NON_NEG_INT_RE = /^\d+$/;

function mustParseInt(s: string, context: string): number {
  if (!s || !NON_NEG_INT_RE.test(s)) {
    throw new Error(`Expected a non-negative integer, got "${s}" (in: "${context}")`);
  }
  const n = parseInt(s, 10);
  if (!Number.isFinite(n)) {
    throw new Error(`Integer overflow parsing "${s}" (in: "${context}")`);
  }
  return n;
}

function assertInRange(n: number, min: number, max: number, context: string): void {
  if (n < min || n > max) {
    throw new RangeError(
      `Value ${n} is out of valid range [${min}, ${max}] (in: "${context}")`
    );
  }
}

function expandRange(start: number, end: number): number[] {
  const out: number[] = [];
  for (let i = start; i <= end; i++) out.push(i);
  return out;
}

function parseSegment(segment: string, field: CronField): number[] {
  const s = segment.trim();
  if (!s) throw new Error(`Empty segment encountered in field "${field}"`);

  const { min } = FIELD_META[field];
  // dayOfWeek accepts 7 as a synonym for Sunday (0) — allow it through validation
  const max = field === "dayOfWeek" ? 7 : FIELD_META[field].max;

  // ── Step value: <base>/<step> ──────────────────────────────────────────────
  const slashIdx = s.indexOf("/");
  if (slashIdx !== -1) {
    const base = s.slice(0, slashIdx);
    const stepStr = s.slice(slashIdx + 1);

    if (!stepStr || stepStr.includes("/")) {
      throw new Error(`Invalid step expression: "${s}"`);
    }

    const step = mustParseInt(stepStr, s);
    if (step === 0) throw new Error(`Step value cannot be zero (in: "${s}")`);

    let rangeStart: number;
    let rangeEnd: number;

    if (base === "*") {
      rangeStart = min;
      rangeEnd = max;
    } else if (base.includes("-")) {
      const dashIdx = base.indexOf("-");
      rangeStart = mustParseInt(base.slice(0, dashIdx), s);
      rangeEnd   = mustParseInt(base.slice(dashIdx + 1), s);
      assertInRange(rangeStart, min, max, s);
      assertInRange(rangeEnd, min, max, s);
      if (rangeStart > rangeEnd) {
        throw new Error(`Range start ${rangeStart} > end ${rangeEnd} (in: "${s}")`);
      }
    } else {
      rangeStart = mustParseInt(base, s);
      assertInRange(rangeStart, min, max, s);
      rangeEnd = max;
    }

    const out: number[] = [];
    for (let i = rangeStart; i <= rangeEnd; i += step) out.push(i);
    return out;
  }

  // ── Range: <start>-<end> ───────────────────────────────────────────────────
  const dashIdx = s.indexOf("-");
  if (dashIdx !== -1) {
    const start = mustParseInt(s.slice(0, dashIdx), s);
    const end   = mustParseInt(s.slice(dashIdx + 1), s);
    assertInRange(start, min, max, s);
    assertInRange(end, min, max, s);
    if (start > end) {
      throw new Error(`Range start ${start} > end ${end} (in: "${s}")`);
    }
    return expandRange(start, end);
  }

  // ── Wildcard ───────────────────────────────────────────────────────────────
  if (s === "*") {
    return expandRange(min, max);
  }

  // ── Single integer ─────────────────────────────────────────────────────────
  const n = mustParseInt(s, s);
  assertInRange(n, min, max, s);
  return [n];
}

function parseField(fieldStr: string, field: CronField): number[] {
  if (!fieldStr) throw new Error(`Empty expression for field "${field}"`);

  const segments = fieldStr.split(",");
  const seen = new Set<number>();

  for (const seg of segments) {
    for (const v of parseSegment(seg, field)) {
      // Normalize dayOfWeek 7 → 0 (both represent Sunday)
      seen.add(field === "dayOfWeek" && v === 7 ? 0 : v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): ParsedCron {
  if (typeof expression !== "string") {
    throw new TypeError(
      `parseCron expects a string, got ${typeof expression}`
    );
  }

  const trimmed = expression.trim();
  if (!trimmed) throw new Error("Cron expression must not be empty");

  const parts = trimmed.split(/\s+/);

  if (parts.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields ` +
      `(minute hour dayOfMonth month dayOfWeek), got ${parts.length}: "${expression}"`
    );
  }

  return {
    minute:     parseField(parts[0], "minute"),
    hour:       parseField(parts[1], "hour"),
    dayOfMonth: parseField(parts[2], "dayOfMonth"),
    month:      parseField(parts[3], "month"),
    dayOfWeek:  parseField(parts[4], "dayOfWeek"),
  };
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly name: keyof CronFields;
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute", min: 0, max: 59 },
  { name: "hour", min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month", min: 1, max: 12 },
  { name: "dayOfWeek", min: 0, max: 6 },
] as const;

function validateInteger(raw: string, fieldName: string, min: number, max: number): number {
  if (!/^\d+$/.test(raw)) {
    throw new Error(`Field "${fieldName}": "${raw}" is not a valid non-negative integer`);
  }
  const value = parseInt(raw, 10);
  if (value < min || value > max) {
    throw new Error(
      `Field "${fieldName}": value ${value} is out of valid range [${min}, ${max}]`
    );
  }
  return value;
}

function expandRange(
  start: number,
  end: number,
  step: number,
  fieldName: string
): number[] {
  if (start > end) {
    throw new Error(
      `Field "${fieldName}": range start ${start} must not exceed range end ${end}`
    );
  }
  if (step < 1) {
    throw new Error(
      `Field "${fieldName}": step value must be a positive integer, got ${step}`
    );
  }
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(segment: string, config: FieldConfig): number[] {
  const { name, min, max } = config;

  if (segment === "") {
    throw new Error(`Field "${name}": encountered an empty segment`);
  }

  // Step expressions: "*/N", "A-B/N", or "A/N"
  if (segment.includes("/")) {
    const slashParts = segment.split("/");
    if (slashParts.length !== 2) {
      throw new Error(`Field "${name}": invalid step expression "${segment}"`);
    }
    const [rangeStr, stepStr] = slashParts;

    if (!/^\d+$/.test(stepStr) || parseInt(stepStr, 10) < 1) {
      throw new Error(
        `Field "${name}": step "${stepStr}" must be a positive integer`
      );
    }
    const step = parseInt(stepStr, 10);

    if (rangeStr === "*") {
      return expandRange(min, max, step, name);
    }

    if (rangeStr.includes("-")) {
      const dashParts = rangeStr.split("-");
      if (dashParts.length !== 2) {
        throw new Error(`Field "${name}": invalid range "${rangeStr}" in step expression`);
      }
      const start = validateInteger(dashParts[0], name, min, max);
      const end = validateInteger(dashParts[1], name, min, max);
      return expandRange(start, end, step, name);
    }

    // "A/N" — start from A, step to max
    const start = validateInteger(rangeStr, name, min, max);
    return expandRange(start, max, step, name);
  }

  // Wildcard
  if (segment === "*") {
    return expandRange(min, max, 1, name);
  }

  // Range: "A-B"
  if (segment.includes("-")) {
    const dashParts = segment.split("-");
    if (dashParts.length !== 2) {
      throw new Error(`Field "${name}": invalid range expression "${segment}"`);
    }
    const start = validateInteger(dashParts[0], name, min, max);
    const end = validateInteger(dashParts[1], name, min, max);
    return expandRange(start, end, 1, name);
  }

  // Single numeric value
  return [validateInteger(segment, name, min, max)];
}

function parseField(raw: string, config: FieldConfig): number[] {
  const trimmed = raw.trim();

  if (trimmed === "") {
    throw new Error(`Field "${config.name}" must not be empty`);
  }

  const segments = trimmed.split(",");
  const valueSet = new Set<number>();

  for (const segment of segments) {
    const s = segment.trim();
    if (s === "") {
      throw new Error(
        `Field "${config.name}": empty segment in comma-separated list "${raw}"`
      );
    }
    const values = parseSegment(s, config);
    for (const v of values) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export function parseCron(expression: string): CronFields {
  if (typeof expression !== "string" || expression.trim() === "") {
    throw new Error("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek), got ${fields.length}`
    );
  }

  return {
    minute: parseField(fields[0], FIELD_CONFIGS[0]),
    hour: parseField(fields[1], FIELD_CONFIGS[1]),
    dayOfMonth: parseField(fields[2], FIELD_CONFIGS[2]),
    month: parseField(fields[3], FIELD_CONFIGS[3]),
    dayOfWeek: parseField(fields[4], FIELD_CONFIGS[4]),
  };
}

export default parseCron;

interface Node<T> {
  key: string;
  value: T;
  prev: Node<T> | null;
  next: Node<T> | null;
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;
  // Sentinel head = most-recently-used end; sentinel tail = least-recently-used end
  private readonly head: Node<T>;
  private readonly tail: Node<T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity)) {
      throw new TypeError(`capacity must be an integer, got: ${capacity}`);
    }
    // Treat capacity < 0 as 0 — nothing is ever stored
    this.capacity = Math.max(0, capacity);
    this.map = new Map();

    // Sentinel nodes eliminate null-checks on every insert/remove
    this.head = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.tail = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key: string): T | undefined {
    const node = this.map.get(key);
    if (node === undefined) {
      return undefined;
    }
    this.moveToFront(node);
    return node.value;
  }

  set(key: string, value: T): void {
    if (this.capacity === 0) {
      return; // Zero-capacity cache; nothing is ever retained
    }

    const existing = this.map.get(key);
    if (existing !== undefined) {
      // Update in-place; no eviction needed regardless of capacity
      existing.value = value;
      this.moveToFront(existing);
      return;
    }

    // Evict the least-recently-used entry before inserting, so we never
    // momentarily exceed capacity (important if capacity === 1)
    if (this.map.size >= this.capacity) {
      this.evictLRU();
    }

    const node: Node<T> = { key, value, prev: null, next: null };
    this.insertAtFront(node);
    this.map.set(key, node);
  }

  get size(): number {
    return this.map.size;
  }

  // ── Private helpers ────────────────────────────────────────────────────────

  private moveToFront(node: Node<T>): void {
    this.removeFromList(node);
    this.insertAtFront(node);
  }

  private insertAtFront(node: Node<T>): void {
    // Insert immediately after the head sentinel
    node.prev = this.head;
    node.next = this.head.next;
    // head.next is always non-null (at minimum it points to tail), but guard anyway
    if (this.head.next !== null) {
      this.head.next.prev = node;
    }
    this.head.next = node;
  }

  private removeFromList(node: Node<T>): void {
    if (node.prev !== null) {
      node.prev.next = node.next;
    }
    if (node.next !== null) {
      node.next.prev = node.prev;
    }
    node.prev = null;
    node.next = null;
  }

  private evictLRU(): void {
    const lru = this.tail.prev;
    // Guard against an empty list (sentinels adjacent to each other)
    if (lru === null || lru === this.head) {
      return;
    }
    this.removeFromList(lru);
    this.map.delete(lru.key);
  }
}

class LRUCache<T> {
  private readonly capacity: number;
  private readonly cache: Map<string, T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 0) {
      throw new RangeError(
        `LRUCache capacity must be a non-negative integer, received: ${capacity}`
      );
    }
    this.capacity = capacity;
    this.cache = new Map<string, T>();
  }

  get(key: string): T | undefined {
    if (!this.cache.has(key)) {
      return undefined;
    }
    // Non-null assertion is safe: has() confirmed presence above
    const value = this.cache.get(key) as T;
    // Re-insert to promote to MRU position (Map preserves insertion order)
    this.cache.delete(key);
    this.cache.set(key, value);
    return value;
  }

  set(key: string, value: T): void {
    // A zero-capacity cache can never store anything
    if (this.capacity === 0) {
      return;
    }

    if (this.cache.has(key)) {
      // Delete first so re-insertion promotes the key to MRU position
      this.cache.delete(key);
    } else if (this.cache.size >= this.capacity) {
      // Evict the LRU entry — the first key inserted into the Map
      const lruKey = this.cache.keys().next().value;
      // Guard: Map should be non-empty here, but never assume
      if (lruKey !== undefined) {
        this.cache.delete(lruKey);
      }
    }

    this.cache.set(key, value);
  }

  get size(): number {
    return this.cache.size;
  }
}

export default LRUCache;

interface DLinkedNode<T> {
  key: string;
  value: T;
  prev: DLinkedNode<T> | null;
  next: DLinkedNode<T> | null;
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, DLinkedNode<T>>;
  // Sentinel head (most recent) and tail (least recent) — never hold real data,
  // eliminates null-checks on splice/insert at the cost of two small objects.
  private readonly head: DLinkedNode<T>;
  private readonly tail: DLinkedNode<T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 1) {
      throw new RangeError(
        `LRUCache capacity must be a positive integer, got: ${capacity}`
      );
    }
    this.capacity = capacity;
    this.map = new Map();

    // Sentinels — cast to satisfy TS; key/value are never read.
    this.head = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.tail = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key: string): T | undefined {
    const node = this.map.get(key);
    if (node === undefined) {
      return undefined;
    }
    this.moveToFront(node);
    return node.value;
  }

  set(key: string, value: T): void {
    const existing = this.map.get(key);

    if (existing !== undefined) {
      existing.value = value;
      this.moveToFront(existing);
      return;
    }

    if (this.map.size >= this.capacity) {
      this.evictLRU();
    }

    const node: DLinkedNode<T> = { key, value, prev: null, next: null };
    this.map.set(key, node);
    this.insertAtFront(node);
  }

  get size(): number {
    return this.map.size;
  }

  // ── Private helpers ──────────────────────────────────────────────────────────

  private insertAtFront(node: DLinkedNode<T>): void {
    node.prev = this.head;
    node.next = this.head.next;
    // head.next is always non-null (sentinel tail at minimum)
    this.head.next!.prev = node;
    this.head.next = node;
  }

  private removeNode(node: DLinkedNode<T>): void {
    // Both pointers are non-null for any real node because sentinels bracket all
    // real nodes — but guard defensively anyway.
    if (node.prev === null || node.next === null) {
      // Attempted to remove a detached or sentinel node — silently skip.
      return;
    }
    node.prev.next = node.next;
    node.next.prev = node.prev;
    node.prev = null;
    node.next = null;
  }

  private moveToFront(node: DLinkedNode<T>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  private evictLRU(): void {
    const lru = this.tail.prev;
    // Guard: if lru is null or is the head sentinel, the list is structurally
    // broken — nothing to evict.
    if (lru === null || lru === this.head) {
      return;
    }
    this.removeNode(lru);
    this.map.delete(lru.key);
  }
}

interface DoublyLinkedNode<T> {
  key: string;
  value: T;
  prev: DoublyLinkedNode<T> | null;
  next: DoublyLinkedNode<T> | null;
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, DoublyLinkedNode<T>>;
  private readonly head: DoublyLinkedNode<T>;
  private readonly tail: DoublyLinkedNode<T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 1) {
      throw new RangeError(`LRUCache capacity must be a positive integer, got: ${capacity}`);
    }

    this.capacity = capacity;
    this.map = new Map();

    this.head = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.tail = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key: string): T | undefined {
    if (typeof key !== "string") {
      return undefined;
    }

    const node = this.map.get(key);
    if (node === undefined) {
      return undefined;
    }

    this.detach(node);
    this.insertAfterHead(node);

    return node.value;
  }

  set(key: string, value: T): void {
    if (typeof key !== "string") {
      throw new TypeError(`LRUCache key must be a string, got: ${typeof key}`);
    }

    const existing = this.map.get(key);

    if (existing !== undefined) {
      existing.value = value;
      this.detach(existing);
      this.insertAfterHead(existing);
      return;
    }

    if (this.map.size >= this.capacity) {
      const lru = this.tail.prev!;
      this.detach(lru);
      this.map.delete(lru.key);
    }

    const node: DoublyLinkedNode<T> = { key, value, prev: null, next: null };
    this.map.set(key, node);
    this.insertAfterHead(node);
  }

  get size(): number {
    return this.map.size;
  }

  has(key: string): boolean {
    return typeof key === "string" && this.map.has(key);
  }

  delete(key: string): boolean {
    if (typeof key !== "string") {
      return false;
    }

    const node = this.map.get(key);
    if (node === undefined) {
      return false;
    }

    this.detach(node);
    this.map.delete(key);
    return true;
  }

  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  keys(): string[] {
    const result: string[] = [];
    let current = this.head.next;
    while (current !== null && current !== this.tail) {
      result.push(current.key);
      current = current.next;
    }
    return result;
  }

  private detach(node: DoublyLinkedNode<T>): void {
    const prev = node.prev!;
    const next = node.next!;
    prev.next = next;
    next.prev = prev;
    node.prev = null;
    node.next = null;
  }

  private insertAfterHead(node: DoublyLinkedNode<T>): void {
    const after = this.head.next!;
    this.head.next = node;
    node.prev = this.head;
    node.next = after;
    after.prev = node;
  }
}

export interface ParsedCron {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type CronField = keyof ParsedCron;

interface FieldRange {
  readonly min: number;
  readonly max: number;
}

const FIELD_RANGES: Record<CronField, FieldRange> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
} as const;

const FIELD_ORDER: readonly CronField[] = [
  "minute", "hour", "dayOfMonth", "month", "dayOfWeek",
] as const;

const INTEGER_RE = /^\d+$/;

function assertInteger(raw: string, context: string): number {
  const trimmed = raw.trim();
  if (!INTEGER_RE.test(trimmed)) {
    throw new Error(`Expected an integer but got "${trimmed}" in ${context}`);
  }
  return parseInt(trimmed, 10);
}

function assertInRange(value: number, range: FieldRange, context: string): void {
  if (value < range.min || value > range.max) {
    throw new Error(
      `Value ${value} is outside the valid range [${range.min}–${range.max}] in ${context}`,
    );
  }
}

function buildStepSequence(start: number, end: number, step: number): number[] {
  if (step <= 0) throw new Error(`Step value must be a positive integer, got ${step}`);
  if (start > end) throw new Error(`Range start ${start} is greater than end ${end}`);
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(segment: string, range: FieldRange, context: string): number[] {
  const s = segment.trim();

  if (s === "") {
    throw new Error(`Empty segment encountered in ${context}`);
  }

  // Step: */N  |  N/N  |  N-M/N
  if (s.includes("/")) {
    const slashIndex = s.indexOf("/");
    const stepRaw = s.slice(slashIndex + 1);
    const step = assertInteger(stepRaw, `step of ${context}`);
    if (step <= 0) {
      throw new Error(`Step must be >= 1, got ${step} in ${context}`);
    }

    const basePart = s.slice(0, slashIndex);

    if (basePart === "*") {
      return buildStepSequence(range.min, range.max, step);
    }

    if (basePart.includes("-")) {
      const dashIndex = basePart.indexOf("-");
      const start = assertInteger(basePart.slice(0, dashIndex), `range-start of ${context}`);
      const end   = assertInteger(basePart.slice(dashIndex + 1), `range-end of ${context}`);
      assertInRange(start, range, context);
      assertInRange(end, range, context);
      return buildStepSequence(start, end, step);
    }

    // N/step — start at N, step to max
    const start = assertInteger(basePart, `step-start of ${context}`);
    assertInRange(start, range, context);
    return buildStepSequence(start, range.max, step);
  }

  // Wildcard
  if (s === "*") {
    return buildStepSequence(range.min, range.max, 1);
  }

  // Range: N-M
  if (s.includes("-")) {
    const dashIndex = s.indexOf("-");
    // Guard against a leading "-" with no left operand
    if (dashIndex === 0) {
      throw new Error(`Range missing start value in ${context}: "${s}"`);
    }
    const start = assertInteger(s.slice(0, dashIndex), `range-start of ${context}`);
    const end   = assertInteger(s.slice(dashIndex + 1), `range-end of ${context}`);
    assertInRange(start, range, context);
    assertInRange(end, range, context);
    if (start > end) {
      throw new Error(
        `Range start ${start} exceeds end ${end} in ${context} — descending ranges are not supported`,
      );
    }
    return buildStepSequence(start, end, 1);
  }

  // Plain integer
  const num = assertInteger(s, context);
  assertInRange(num, range, context);
  return [num];
}

function parseField(raw: string, range: FieldRange, fieldName: string): number[] {
  const trimmed = raw.trim();

  if (trimmed === "") {
    throw new Error(`Field "${fieldName}" is empty`);
  }

  // Comma-separated list — each element is independently parsed
  const parts = trimmed.split(",");
  const seen = new Set<number>();

  for (const part of parts) {
    if (part.trim() === "") {
      throw new Error(
        `Field "${fieldName}" contains an empty element in the comma list: "${trimmed}"`,
      );
    }
    for (const value of parseSegment(part, range, fieldName)) {
      seen.add(value);
    }
  }

  // Return a deduplicated, sorted array — predictable, diff-friendly
  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): ParsedCron {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, received ${typeof expression}`);
  }

  const trimmed = expression.trim();

  if (trimmed === "") {
    throw new Error("Cron expression must not be empty");
  }

  // Split on one-or-more whitespace characters
  const parts = trimmed.split(/\s+/);

  if (parts.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 space-separated fields; ` +
      `received ${parts.length}: "${expression}"`,
    );
  }

  const result = {} as ParsedCron;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    const fieldRange = FIELD_RANGES[fieldName];
    try {
      result[fieldName] = parseField(parts[i], fieldRange, fieldName);
    } catch (err) {
      // Re-wrap with field context so callers always know where the problem is
      const message = err instanceof Error ? err.message : String(err);
      throw new Error(`Failed to parse "${fieldName}" field (value: "${parts[i]}"): ${message}`);
    }
  }

  return result;
}

interface Node<T> {
  key: string;
  value: T;
  prev: Node<T> | null;
  next: Node<T> | null;
}

/**
 * LRU Cache backed by a doubly-linked list + Map for O(1) get and set.
 *
 * Sentinel head (MRU end) and tail (LRU end) eliminate null-checks on
 * boundary operations and prevent accidental eviction of non-existent nodes.
 */
export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;
  // dummy sentinel: head.next = most-recently-used real node
  private readonly head: Node<T>;
  // dummy sentinel: tail.prev = least-recently-used real node
  private readonly tail: Node<T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 0) {
      throw new RangeError(
        `LRUCache capacity must be a non-negative integer, received: ${capacity}`,
      );
    }
    this.capacity = capacity;
    this.map = new Map();

    // Sentinels carry no real data; using `unknown` cast avoids polluting the
    // generic with undefined while keeping Node<T> uniform throughout.
    this.head = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.tail = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  /**
   * Returns the cached value for `key`, promoting it to most-recently-used.
   * Returns `undefined` if the key is not present.
   */
  get(key: string): T | undefined {
    const node = this.map.get(key);
    if (node === undefined) {
      return undefined;
    }
    this.moveToFront(node);
    return node.value;
  }

  /**
   * Inserts or updates `key` → `value`, marking it most-recently-used.
   * If the cache is at capacity, the least-recently-used entry is evicted first.
   * A capacity of 0 is a valid no-op cache (nothing is ever stored).
   */
  set(key: string, value: T): void {
    // Zero-capacity cache: writes are intentional no-ops; avoids an
    // immediate eviction loop that would silently discard every write.
    if (this.capacity === 0) {
      return;
    }

    const existing = this.map.get(key);
    if (existing !== undefined) {
      // Key already present: update in-place and promote.
      existing.value = value;
      this.moveToFront(existing);
      return;
    }

    const node: Node<T> = { key, value, prev: null, next: null };
    this.insertAtFront(node);
    this.map.set(key, node);

    if (this.map.size > this.capacity) {
      // tail.prev is guaranteed to be a real node here because:
      //   - capacity >= 1 (checked above)
      //   - map.size just became capacity + 1 >= 2, so at least one real node exists
      const lru = this.tail.prev as Node<T>;
      this.removeNode(lru);
      this.map.delete(lru.key);
    }
  }

  // ─── Private helpers ────────────────────────────────────────────────────────

  private insertAtFront(node: Node<T>): void {
    node.prev = this.head;
    node.next = this.head.next;
    // head.next is always non-null (initialised to tail, never set to null)
    (this.head.next as Node<T>).prev = node;
    this.head.next = node;
  }

  /** Unlinks `node` from wherever it currently sits in the list. */
  private removeNode(node: Node<T>): void {
    // Real nodes always have prev/next set (to another real node or a sentinel),
    // so these non-null assertions are structurally guaranteed.
    (node.prev as Node<T>).next = node.next;
    (node.next as Node<T>).prev = node.prev;
    // Null out pointers to avoid retaining references to the rest of the list.
    node.prev = null;
    node.next = null;
  }

  private moveToFront(node: Node<T>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }
}

interface Node<T> {
  key: string;
  value: T;
  prev: Node<T> | null;
  next: Node<T> | null;
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;
  private readonly head: Node<T>;
  private readonly tail: Node<T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 1) {
      throw new RangeError(`LRUCache capacity must be a positive integer, got: ${capacity}`);
    }

    this.capacity = capacity;
    this.map = new Map();

    this.head = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.tail = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key: string): T | undefined {
    if (typeof key !== "string") {
      return undefined;
    }

    const node = this.map.get(key);
    if (node === undefined) {
      return undefined;
    }

    this.moveToFront(node);
    return node.value;
  }

  set(key: string, value: T): void {
    if (typeof key !== "string") {
      throw new TypeError(`LRUCache key must be a string, got: ${typeof key}`);
    }

    const existing = this.map.get(key);

    if (existing !== undefined) {
      existing.value = value;
      this.moveToFront(existing);
      return;
    }

    const node: Node<T> = { key, value, prev: null, next: null };
    this.map.set(key, node);
    this.insertAtFront(node);

    if (this.map.size > this.capacity) {
      this.evictLRU();
    }
  }

  get size(): number {
    return this.map.size;
  }

  has(key: string): boolean {
    return typeof key === "string" && this.map.has(key);
  }

  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  private insertAtFront(node: Node<T>): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  private removeNode(node: Node<T>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    node.prev = null;
    node.next = null;
  }

  private moveToFront(node: Node<T>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  private evictLRU(): void {
    const lru = this.tail.prev;
    if (lru === null || lru === this.head) {
      return;
    }
    this.removeNode(lru);
    this.map.delete(lru.key);
  }
}

interface Node<T> {
  key: string;
  value: T;
  prev: Node<T> | null;
  next: Node<T> | null;
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;
  private head: Node<T> | null; // most recently used
  private tail: Node<T> | null; // least recently used

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 1) {
      throw new RangeError(`Capacity must be a positive integer, got: ${capacity}`);
    }
    this.capacity = capacity;
    this.map = new Map();
    this.head = null;
    this.tail = null;
  }

  get(key: string): T | undefined {
    if (typeof key !== "string") return undefined;

    const node = this.map.get(key);
    if (node === undefined) return undefined;

    this.moveToHead(node);
    return node.value;
  }

  set(key: string, value: T): void {
    if (typeof key !== "string") {
      throw new TypeError(`Key must be a string, got: ${typeof key}`);
    }
    if (value === undefined) {
      throw new TypeError("Value must not be undefined; use delete to remove entries");
    }

    const existing = this.map.get(key);

    if (existing !== undefined) {
      existing.value = value;
      this.moveToHead(existing);
      return;
    }

    const node: Node<T> = { key, value, prev: null, next: null };
    this.map.set(key, node);
    this.prepend(node);

    if (this.map.size > this.capacity) {
      this.evict();
    }
  }

  get size(): number {
    return this.map.size;
  }

  has(key: string): boolean {
    return typeof key === "string" && this.map.has(key);
  }

  clear(): void {
    this.map.clear();
    this.head = null;
    this.tail = null;
  }

  // Insert node at the head (most recently used position).
  private prepend(node: Node<T>): void {
    node.prev = null;
    node.next = this.head;

    if (this.head !== null) {
      this.head.prev = node;
    }

    this.head = node;

    if (this.tail === null) {
      this.tail = node;
    }
  }

  // Detach node from its current position in the list.
  private detach(node: Node<T>): void {
    if (node.prev !== null) {
      node.prev.next = node.next;
    } else {
      // node was the head
      this.head = node.next;
    }

    if (node.next !== null) {
      node.next.prev = node.prev;
    } else {
      // node was the tail
      this.tail = node.prev;
    }

    node.prev = null;
    node.next = null;
  }

  // Move an existing node to the head.
  private moveToHead(node: Node<T>): void {
    if (node === this.head) return;
    this.detach(node);
    this.prepend(node);
  }

  // Remove the least recently used node (tail).
  private evict(): void {
    if (this.tail === null) return;
    const lru = this.tail;
    this.detach(lru);
    this.map.delete(lru.key);
  }
}

type Primitive = string | number | boolean | null | undefined | bigint | symbol;

type NestedObject = {
  [key: string]: Primitive | NestedObject | Array<unknown>;
};

type FlattenedObject = Record<string, Primitive | Array<unknown>>;

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  input: unknown,
  options: { delimiter?: string; maxDepth?: number } = {}
): FlattenedObject {
  const { delimiter = ".", maxDepth = Infinity } = options;

  if (delimiter === "" ) {
    throw new RangeError("delimiter must be a non-empty string");
  }

  if (typeof maxDepth !== "number" || maxDepth < 0 || !isFinite(maxDepth)) {
    throw new RangeError("maxDepth must be a non-negative finite number");
  }

  if (!isPlainObject(input)) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${
        input === null ? "null" : typeof input
      }`
    );
  }

  const result: FlattenedObject = {};
  const seen = new WeakSet<object>();

  function recurse(current: unknown, prefix: string, depth: number): void {
    if (!isPlainObject(current)) {
      result[prefix] = current as Primitive | Array<unknown>;
      return;
    }

    if (seen.has(current)) {
      throw new TypeError(
        `Circular reference detected at key: "${prefix}"`
      );
    }

    const keys = Object.keys(current);

    if (depth >= maxDepth || keys.length === 0) {
      if (prefix !== "") {
        result[prefix] = current as unknown as NestedObject & Primitive;
      }
      return;
    }

    seen.add(current);

    for (const key of keys) {
      if (!Object.prototype.hasOwnProperty.call(current, key)) continue;

      const value = (current as Record<string, unknown>)[key];
      const newKey = prefix === "" ? key : `${prefix}${delimiter}${key}`;

      if (isPlainObject(value)) {
        recurse(value, newKey, depth + 1);
      } else {
        result[newKey] = value as Primitive | Array<unknown>;
      }
    }

    seen.delete(current);
  }

  recurse(input, "", 0);

  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined | bigint | symbol;

type NestedObject = {
  [key: string]: Primitive | NestedObject | unknown[] | unknown;
};

type FlatObject = Record<string, Primitive | unknown[]>;

function flattenObject(
  input: unknown,
  prefix: string = "",
  result: FlatObject = {},
  visited: WeakSet<object> = new WeakSet()
): FlatObject {
  if (input === null || input === undefined) {
    if (prefix !== "") {
      result[prefix] = input as Primitive;
    }
    return result;
  }

  if (typeof input !== "object" || Array.isArray(input)) {
    if (prefix !== "") {
      result[prefix] = input as Primitive | unknown[];
    }
    return result;
  }

  const obj = input as Record<string, unknown>;

  if (visited.has(obj)) {
    throw new TypeError(
      `Circular reference detected at key: "${prefix}"`
    );
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix !== "") {
      result[prefix] = {} as unknown as Primitive;
    }
    return result;
  }

  visited.add(obj);

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) {
      continue;
    }

    const sanitizedKey = String(key);
    const newPrefix = prefix === "" ? sanitizedKey : `${prefix}.${sanitizedKey}`;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value, newPrefix, result, visited);
    } else {
      result[newPrefix] = value as Primitive | unknown[];
    }
  }

  visited.delete(obj);

  return result;
}

export default flattenObject;
